import React, { useState, useEffect, useRef } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { Search, KeyRound, CreditCard, UserCircle, Wifi, FileText, X, Loader2 } from 'lucide-react';
import useAuthStore from '../store/useAuthStore';
import { fetchVaultItems } from '../lib/api';
import { decryptData } from '../lib/crypto';
import clsx from 'clsx';
import { useNavigate } from 'react-router-dom';

export default function CommandPalette() {
    const [isOpen, setIsOpen] = useState(false);
    const [query, setQuery] = useState('');
    const [items, setItems] = useState([]);
    const [loading, setLoading] = useState(false);
    const { masterKey } = useAuthStore();
    const inputRef = useRef(null);
    const navigate = useNavigate();

    useEffect(() => {
        const handleKeyDown = (e) => {
            if ((e.metaKey || e.ctrlKey) && e.key === 'k') {
                e.preventDefault();
                setIsOpen(true);
            }
            if (e.key === 'Escape') setIsOpen(false);
        };
        window.addEventListener('keydown', handleKeyDown);
        return () => window.removeEventListener('keydown', handleKeyDown);
    }, []);

    useEffect(() => {
        if (!isOpen) {
            setQuery('');
            return;
        }
        const load = async () => {
            setLoading(true);
            try {
                const raw = await fetchVaultItems();
                const dec = raw.filter(i => !i.isDeleted).map(i => {
                    const p = decryptData(i.encryptedBlob, masterKey);
                    return p ? { _id: i._id, itemType: i.itemType || 'LOGIN', ...p } : null;
                }).filter(Boolean);
                setItems(dec);
            } catch (e) {
                console.error(e);
            } finally {
                setLoading(false);
            }
        };
        load();
        setTimeout(() => inputRef.current?.focus(), 100);
    }, [isOpen, masterKey]);

    const filtered = items.filter(i => {
        const str = `${i.appName} ${i.username || ''} ${i.category || ''} ${(i.tags || []).join(' ')}`.toLowerCase();
        return str.includes(query.toLowerCase());
    });

    const getIcon = (type) => {
        switch (type) {
            case 'CREDIT_CARD': return <CreditCard size={18} className="text-secondary" />;
            case 'IDENTITY':    return <UserCircle size={18} className="text-primary" />;
            case 'WIFI':        return <Wifi size={18} className="text-sky-400" />;
            case 'SECURE_NOTE': return <FileText size={18} className="text-orange-400" />;
            default:            return <KeyRound size={18} className="text-primary" />;
        }
    };

    if (!isOpen) return null;

    return (
        <div className="fixed inset-0 z-[150] flex items-start justify-center pt-[15vh] px-4 bg-background/80 backdrop-blur-md">
            <motion.div
                initial={{ opacity: 0, scale: 0.95, y: -20 }}
                animate={{ opacity: 1, scale: 1, y: 0 }}
                exit={{ opacity: 0, scale: 0.95, y: 10 }}
                transition={{ type: 'spring', damping: 25, stiffness: 300 }}
                className="w-full max-w-2xl bg-black/40 dark:bg-black/60 rounded-3xl overflow-hidden glass-panel border border-border/50 shadow-2xl flex flex-col"
            >
                <div className="flex items-center px-4 py-4 border-b border-border/50">
                    <Search className="text-muted-foreground mr-3" size={24} />
                    <input
                        ref={inputRef}
                        value={query}
                        onChange={e => setQuery(e.target.value)}
                        placeholder="Search passwords, notes, credit cards..."
                        className="flex-1 bg-transparent border-none outline-none text-lg text-foreground placeholder:text-muted-foreground"
                    />
                    {loading && <Loader2 className="animate-spin text-primary ml-2" size={20} />}
                    <button onClick={() => setIsOpen(false)} className="ml-2 p-1.5 rounded-xl hover:bg-white/10 text-muted-foreground transition-all">
                        <X size={20} />
                    </button>
                </div>

                <div className="max-h-[50vh] overflow-y-auto custom-scrollbar p-2">
                    {query && filtered.length === 0 && !loading && (
                        <div className="p-8 text-center text-muted-foreground flex flex-col items-center">
                            <Search size={32} className="mb-3 opacity-50" />
                            <p className="font-bold">No results found for "{query}"</p>
                        </div>
                    )}

                    {!query && !loading && (
                        <div className="p-4 text-xs font-bold uppercase tracking-widest text-muted-foreground ml-2">
                            Type to search vault...
                        </div>
                    )}

                    {filtered.length > 0 && query && (
                        <div className="space-y-1">
                            {filtered.map(item => (
                                <button
                                    key={item._id}
                                    onClick={() => {
                                        setIsOpen(false);
                                        navigate('/dashboard'); // Go to dashboard so they can find it
                                        // A future improvement would be to open the ItemModal directly from here.
                                    }}
                                    className="w-full flex items-center gap-4 p-3 rounded-xl hover:bg-primary/10 transition-colors text-left group"
                                >
                                    <div className="w-10 h-10 rounded-xl bg-white/5 border border-white/10 flex items-center justify-center shrink-0">
                                        {getIcon(item.itemType || 'LOGIN')}
                                    </div>
                                    <div className="flex-1 min-w-0">
                                        <p className="font-bold truncate text-foreground group-hover:text-primary transition-colors">{item.appName}</p>
                                        <p className="text-xs text-muted-foreground truncate">{item.username || item.itemType || 'Item'}</p>
                                    </div>
                                    <div className="text-[10px] uppercase font-bold tracking-widest text-muted-foreground opacity-50 group-hover:opacity-100 transition-opacity">
                                        {item.category}
                                    </div>
                                </button>
                            ))}
                        </div>
                    )}
                </div>

                <div className="px-4 py-3 bg-black/20 border-t border-border/50 text-[10px] font-bold uppercase tracking-widest text-muted-foreground flex items-center justify-between">
                    <div className="flex gap-4">
                        <span className="flex items-center gap-1.5"><kbd className="bg-white/10 px-1.5 py-0.5 rounded">↑</kbd><kbd className="bg-white/10 px-1.5 py-0.5 rounded">↓</kbd> Navigate</span>
                        <span className="flex items-center gap-1.5"><kbd className="bg-white/10 px-1.5 py-0.5 rounded">↵</kbd> Open</span>
                    </div>
                    <span><kbd className="bg-white/10 px-1.5 py-0.5 rounded text-primary">ESC</kbd> Close</span>
                </div>
            </motion.div>
        </div>
    );
}

import React from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { AlertTriangle, X } from 'lucide-react';

/**
 * Professional in-app Confirm Dialog to replace window.confirm()
 * Usage:
 *   <ConfirmDialog
 *     isOpen={showConfirm}
 *     title="Delete Item?"
 *     message="This action cannot be undone."
 *     confirmLabel="Delete"
 *     confirmVariant="danger"   // 'danger' | 'primary'
 *     onConfirm={() => { doAction(); setShowConfirm(false); }}
 *     onCancel={() => setShowConfirm(false)}
 *   />
 */
export default function ConfirmDialog({
    isOpen,
    title = 'Are you sure?',
    message = 'This action cannot be undone.',
    confirmLabel = 'Confirm',
    cancelLabel = 'Cancel',
    confirmVariant = 'danger',
    onConfirm,
    onCancel,
    icon: Icon = AlertTriangle,
}) {
    if (!isOpen) return null;

    const confirmClasses =
        confirmVariant === 'danger'
            ? 'bg-red-500 hover:bg-red-600 text-white shadow-lg shadow-red-500/30'
            : 'bg-primary hover:bg-primary/90 text-primary-foreground shadow-lg shadow-primary/30';

    return (
        <AnimatePresence>
            {isOpen && (
                <motion.div
                    initial={{ opacity: 0 }}
                    animate={{ opacity: 1 }}
                    exit={{ opacity: 0 }}
                    className="fixed inset-0 z-[200] flex items-center justify-center p-4 bg-black/60 backdrop-blur-sm"
                    onClick={onCancel}
                >
                    <motion.div
                        initial={{ scale: 0.9, opacity: 0, y: 16 }}
                        animate={{ scale: 1, opacity: 1, y: 0 }}
                        exit={{ scale: 0.9, opacity: 0, y: 16 }}
                        transition={{ type: 'spring', damping: 24, stiffness: 320 }}
                        className="glass-panel border border-border w-full max-w-sm rounded-3xl shadow-2xl overflow-hidden"
                        onClick={(e) => e.stopPropagation()}
                    >
                        {/* Top accent */}
                        <div className={`h-1 w-full ${confirmVariant === 'danger' ? 'bg-gradient-to-r from-red-500/40 via-red-500 to-red-500/40' : 'bg-gradient-to-r from-primary/40 via-primary to-primary/40'}`} />

                        <div className="p-6">
                            {/* Icon + Title */}
                            <div className="flex items-start gap-4 mb-4">
                                <div className={`p-3 rounded-2xl shrink-0 ${confirmVariant === 'danger' ? 'bg-red-500/10 text-red-500' : 'bg-primary/10 text-primary'}`}>
                                    <Icon size={22} />
                                </div>
                                <div className="flex-1 pt-0.5">
                                    <h3 className="font-bold text-lg leading-tight mb-1">{title}</h3>
                                    <p className="text-sm text-muted-foreground leading-relaxed">{message}</p>
                                </div>
                                <button
                                    onClick={onCancel}
                                    className="p-1.5 rounded-xl hover:bg-black/5 dark:hover:bg-white/5 text-muted-foreground transition-colors shrink-0"
                                >
                                    <X size={16} />
                                </button>
                            </div>

                            {/* Actions */}
                            <div className="flex gap-3 mt-6">
                                <button
                                    onClick={onCancel}
                                    className="flex-1 py-2.5 rounded-xl border border-border text-sm font-semibold text-muted-foreground hover:text-foreground hover:bg-black/5 dark:hover:bg-white/5 transition-colors"
                                >
                                    {cancelLabel}
                                </button>
                                <motion.button
                                    whileTap={{ scale: 0.97 }}
                                    onClick={onConfirm}
                                    className={`flex-1 py-2.5 rounded-xl text-sm font-bold transition-all ${confirmClasses}`}
                                >
                                    {confirmLabel}
                                </motion.button>
                            </div>
                        </div>
                    </motion.div>
                </motion.div>
            )}
        </AnimatePresence>
    );
}

import React, { useState } from 'react';
import { Outlet, useLocation } from 'react-router-dom';
import Sidebar from './Sidebar';
import NotificationDropdown from './NotificationDropdown';
import { Menu, Sun, Moon, Shield } from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';
import { useTheme } from './ThemeProvider';
import clsx from 'clsx';
import useAuthStore from '../store/useAuthStore';
import useToastStore from '../store/useToastStore';
import { useEffect, useCallback } from 'react';
import CommandPalette from './CommandPalette';
import useNotificationStore from '../store/useNotificationStore';
import { API_URL } from '../lib/api';

const ActivityManager = () => {
    const { lastActivity, updateActivity, autoLockTimer, lockVault } = useAuthStore();
    const { addToast } = useToastStore();

    useEffect(() => {
        let lastUpdate = Date.now();
        const handleUserActivity = () => {
            const now = Date.now();
            // Only update activity state if at least 2 seconds have passed since the last update
            // to avoid excessive re-renders during mouse movement.
            if (now - lastUpdate > 2000) {
                updateActivity();
                lastUpdate = now;
            }
        };

        const events = ['mousedown', 'keydown', 'scroll', 'touchstart', 'mousemove'];
        events.forEach(event => window.addEventListener(event, handleUserActivity, { passive: true }));

        const checkInactivity = setInterval(() => {
            const now = Date.now();
            const elapsedSeconds = Math.floor((now - lastActivity) / 1000);
            const limitSeconds = autoLockTimer * 60;

            if (elapsedSeconds >= limitSeconds) {
                lockVault();
                addToast(`Vault locked due to ${autoLockTimer}m inactivity`, "info");
                clearInterval(checkInactivity);
            }
        }, 1000);

        return () => {
            events.forEach(event => window.removeEventListener(event, handleUserActivity));
            clearInterval(checkInactivity);
        };
    }, [lastActivity, autoLockTimer, lockVault, addToast, updateActivity]);

    return null;
};

const TicketNotificationsManager = () => {
    const { user } = useAuthStore();
    const { addNotification } = useNotificationStore();

    useEffect(() => {
        if (!user) return;
        const checkKey = `lastTicketCheck_${user.uid}`;

        const checkTickets = async () => {
            try {
                const endpoint = (user.role === 'admin' || user.role === 'superadmin') ? '/admin/tickets' : '/support';
                const res = await fetch(`${API_URL}${endpoint}`, { credentials: 'include' });
                if (!res.ok) return;
                const tickets = await res.json();

                let lastCheck = localStorage.getItem(checkKey);

                // If it's the very first time, just store the latest ticket time and don't notify to avoid spam
                if (!lastCheck) {
                    let maxTime = Date.now();
                    tickets.forEach(t => {
                        const tTime = Math.max(new Date(t.createdAt).getTime(), new Date(t.updatedAt).getTime());
                        maxTime = Math.max(maxTime, tTime);
                    });
                    localStorage.setItem(checkKey, maxTime.toString());
                    return; 
                }

                lastCheck = parseInt(lastCheck);
                let latestTime = lastCheck;

                tickets.forEach(ticket => {
                    const createdTime = new Date(ticket.createdAt).getTime();
                    const updatedTime = new Date(ticket.updatedAt).getTime();

                    // ADMIN NOTIFICATIONS: Only show to admins/superadmins
                    if (user.role === 'admin' || user.role === 'superadmin') {
                        if (createdTime > lastCheck && ticket.status === 'OPEN' && ticket.userId?._id !== user.uid) {
                            addNotification(`New Support Request`, `Subject: ${ticket.subject}`, 'warning');
                            latestTime = Math.max(latestTime, createdTime);
                        }
                    } 

                    // USER NOTIFICATIONS: Only show to regular users
                    if (user.role !== 'admin' && user.role !== 'superadmin') {
                        if (updatedTime > lastCheck) {
                            if (ticket.status === 'RESOLVED') {
                                addNotification('Support: Ticket Resolved', `Ticket "${ticket.subject}" is now closed.`, 'success');
                                latestTime = Math.max(latestTime, updatedTime);
                            } else if (ticket.adminReply && updatedTime > createdTime) {
                                // Only notify if updatedAt is greater than createdAt (meaning it was modified/replied by admin)
                                addNotification('Support: New Reply', `Admin replied to: ${ticket.subject}`, 'info');
                                latestTime = Math.max(latestTime, updatedTime);
                            }
                        }
                    }
                });

                if (latestTime > lastCheck) {
                    localStorage.setItem(checkKey, latestTime.toString());
                }
            } catch (error) {
                // Silently fail polling
            }
        };

        checkTickets();
        const interval = setInterval(checkTickets, 30000);
        return () => clearInterval(interval);
    }, [user, addNotification]);

    return null;
};

const DashboardLayout = () => {
    const [isSidebarOpen, setIsSidebarOpen] = useState(false);
    const { theme, setTheme } = useTheme();
    const { user } = useAuthStore();
    const location = useLocation();

    return (
        <div className="flex h-screen bg-background text-foreground overflow-hidden">
            {/* Background Managers (No-UI) */}
            <ActivityManager />
            <TicketNotificationsManager />

            {/* Global Search CMD+K Palette */}
            <CommandPalette />

            {/* Nav Sidebar Component */}
            <Sidebar isOpen={isSidebarOpen} onClose={() => setIsSidebarOpen(false)} />

            {/* Main Content Area */}
            <main className="flex-1 flex flex-col relative overflow-hidden bg-background">
                {/* Global Header */}
                <header className="h-20 border-b border-border flex items-center justify-between px-4 lg:px-8 glass-panel sticky top-0 z-40 bg-background/80 backdrop-blur-md">
                    <div className="flex items-center gap-3 flex-1 lg:hidden">
                        <button 
                            className="p-2 text-foreground hover:bg-black/5 dark:hover:bg-white/5 rounded-xl transition-colors"
                            onClick={() => setIsSidebarOpen(true)}
                        >
                            <Menu size={24} />
                        </button>
                        <Shield size={24} className="text-primary lg:hidden" />
                    </div>

                    <div className="hidden lg:flex items-center gap-4 text-xs font-bold uppercase tracking-widest text-muted-foreground">
                        <span className="text-primary italic">Status:</span> 
                        <span className="flex items-center gap-1.5 text-green-500">
                           <div className="w-1.5 h-1.5 rounded-full bg-green-500 animate-pulse" /> End-to-End Encrypted
                        </span>
                    </div>

                    <div className="flex items-center gap-2 sm:gap-3 lg:gap-5 shrink-0 ml-auto">
                        <NotificationDropdown />

                        <motion.button 
                            whileHover={{ scale: 1.1 }} whileTap={{ scale: 0.9 }}
                            onClick={() => setTheme(theme === 'dark' ? 'light' : 'dark')}
                            className="p-2.5 rounded-full hover:bg-black/5 dark:hover:bg-white/5 transition-colors text-muted-foreground hover:text-foreground border border-border/50"
                        >
                            {theme === 'dark' ? <Sun size={20} /> : <Moon size={20} />}
                        </motion.button>

                        <div className="h-8 w-[1px] bg-border/50 mx-1 hidden sm:block" />

                        <div className="flex items-center gap-3">
                            <div className="text-right hidden sm:block">
                                <p className="text-xs font-bold leading-none mb-1">{user?.name || 'Account'}</p>
                                <p className="text-[10px] text-muted-foreground">Pro Member</p>
                            </div>
                            <div className="w-9 h-9 rounded-xl bg-gradient-to-br from-primary to-primary/60 flex items-center justify-center text-primary-foreground font-bold shadow-lg shadow-primary/20">
                                {(user?.name || user?.email)?.charAt(0).toUpperCase()}
                            </div>
                        </div>
                    </div>
                </header>

                {/* Page Content Holder */}
                <div className="flex-1 overflow-auto relative custom-scrollbar">
                    {/* Background Decorative Gradients */}
                    <div className="absolute top-0 right-0 w-[500px] h-[500px] bg-primary/5 rounded-full blur-[120px] -z-10 pointer-events-none opacity-50" />
                    <div className="absolute bottom-0 left-0 w-[400px] h-[400px] bg-primary/3 rounded-full blur-[100px] -z-10 pointer-events-none opacity-30" />

                    {/* Route Transitions */}
                    <AnimatePresence mode="wait">
                         <motion.div
                            key={location.pathname}
                            initial={{ opacity: 0, scale: 0.98, y: 5 }}
                            animate={{ opacity: 1, scale: 1, y: 0 }}
                            exit={{ opacity: 0, scale: 1.02, y: -5 }}
                            transition={{ duration: 0.2, ease: [0.22, 1, 0.36, 1] }}
                            className="h-full"
                         >
                            <Outlet />
                         </motion.div>
                    </AnimatePresence>
                </div>
            </main>
        </div>
    );
};

export default DashboardLayout;

import React, { useState, useEffect } from 'react';
import { motion } from 'framer-motion';
import { Smartphone, Laptop, Globe, LogOut, ShieldAlert, CheckCircle2, Loader2 } from 'lucide-react';
import useToastStore from '../store/useToastStore';
import { API_URL } from '../lib/api';

export default function DeviceManager() {
    const [sessions, setSessions] = useState([]);
    const [loading, setLoading] = useState(true);
    const { addToast } = useToastStore();

    const fetchSessions = async () => {
        try {
            const res = await fetch(`${API_URL}/devices`, { credentials: 'include' });
            if (res.ok) {
                const data = await res.json();
                setSessions(data);
            }
        } catch (error) {
            console.error(error);
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        fetchSessions();
    }, []);

    const revokeSession = async (sessionId) => {
        try {
            const res = await fetch(`${API_URL}/devices/${sessionId}`, {
                method: 'DELETE',
                credentials: 'include'
            });
            if (res.ok) {
                addToast('Device disconnected', 'success');
                setSessions(s => s.filter(x => x.id !== sessionId));
            } else {
                addToast('Failed to disconnect device', 'error');
            }
        } catch (e) {
            addToast('Error disconnecting device', 'error');
        }
    };

    const revokeAllOthers = async () => {
        try {
            const res = await fetch(`${API_URL}/devices/revoke-all`, {
                method: 'POST',
                credentials: 'include'
            });
            if (res.ok) {
                addToast('All other devices disconnected', 'success');
                setSessions(s => s.filter(x => x.isCurrent));
            }
        } catch (e) {
            addToast('Error disconnecting devices', 'error');
        }
    };

    if (loading) {
        return <div className="p-8 flex justify-center"><Loader2 className="animate-spin text-primary" /></div>;
    }

    return (
        <section className="glass-panel p-8 rounded-3xl border border-border space-y-6">
            <div className="flex items-center justify-between border-b border-border/50 pb-4">
                <div className="flex items-center gap-3">
                    <div className="p-2 bg-primary/10 rounded-lg text-primary"><Smartphone size={20} /></div>
                    <h2 className="text-xl font-bold">Active Devices</h2>
                </div>
                {sessions.length > 1 && (
                    <button
                        onClick={revokeAllOthers}
                        className="text-xs font-bold bg-red-500/10 text-red-500 hover:bg-red-500/20 px-3 py-1.5 rounded-lg transition-colors flex items-center gap-1.5"
                    >
                        <ShieldAlert size={14} /> Revoke Others
                    </button>
                )}
            </div>

            <div className="space-y-4">
                {sessions.map(session => (
                    <div key={session.id} className="flex items-center justify-between p-4 bg-black/5 dark:bg-white/5 rounded-2xl border border-border/50">
                        <div className="flex items-center gap-4">
                            <div className="p-3 bg-background rounded-xl text-primary shadow-sm border border-border/50">
                                {session.browser?.toLowerCase().includes('mobile') ? <Smartphone size={24} /> : <Laptop size={24} />}
                            </div>
                            <div>
                                <div className="flex items-center gap-2">
                                    <h4 className="font-bold text-sm">
                                        {session.browser !== 'Unknown' ? session.browser : 'Unknown Browser'}
                                    </h4>
                                    {session.isCurrent && (
                                        <span className="text-[9px] uppercase tracking-widest font-bold bg-green-500/20 text-green-500 px-2 py-0.5 rounded-md flex items-center gap-1">
                                            <CheckCircle2 size={10} /> Current
                                        </span>
                                    )}
                                </div>
                                <div className="flex items-center gap-3 text-xs text-muted-foreground mt-1">
                                    <span className="flex items-center gap-1"><Globe size={12} /> {session.ip || 'Unknown IP'}</span>
                                    <span>•</span>
                                    <span>Last active: {new Date(session.lastActive).toLocaleDateString()}</span>
                                </div>
                            </div>
                        </div>

                        {!session.isCurrent && (
                            <button
                                onClick={() => revokeSession(session.id)}
                                className="p-2 text-muted-foreground hover:text-red-500 hover:bg-red-500/10 rounded-xl transition-colors"
                                title="Log out device"
                            >
                                <LogOut size={18} />
                            </button>
                        )}
                    </div>
                ))}
            </div>
        </section>
    );
}

import React, { useState, useEffect, useCallback } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import {
    Star, Edit3, Trash2, Copy, ShieldCheck, Loader2,
    CreditCard, UserCircle, Wifi, FileText, KeyRound,
    Share2, Eye, EyeOff, Check, Clock
} from 'lucide-react';
import clsx from 'clsx';
import { TOTP } from 'otpauth';
import { marked } from 'marked';
import DOMPurify from 'dompurify';
import useToastStore from '../store/useToastStore';

const fadeUpItem = {
    hidden: { opacity: 0, y: 20 },
    show: { opacity: 1, y: 0, transition: { type: 'spring', stiffness: 300, damping: 24 } }
};

// Relative time formatter
function timeAgo(dateStr) {
    if (!dateStr) return null;
    const diff = Date.now() - new Date(dateStr).getTime();
    const mins = Math.floor(diff / 60000);
    const hrs = Math.floor(diff / 3600000);
    const days = Math.floor(diff / 86400000);
    if (mins < 1) return 'just now';
    if (mins < 60) return `${mins}m ago`;
    if (hrs < 24) return `${hrs}h ago`;
    if (days < 30) return `${days}d ago`;
    return new Date(dateStr).toLocaleDateString('en-IN', { day: 'numeric', month: 'short' });
}

// Copy-with-feedback hook
function useCopyFeedback() {
    const [copiedKey, setCopiedKey] = useState(null);
    const { addToast } = useToastStore();
    const copy = useCallback((text, label, key) => {
        if (!text) return;
        navigator.clipboard.writeText(text);
        addToast(`${label} copied!`, 'success');
        setCopiedKey(key);
        setTimeout(() => setCopiedKey(null), 2000);
    }, [addToast]);
    return { copiedKey, copy };
}

function CopyBtn({ text, label, copyKey, copiedKey, onCopy, className = '' }) {
    const isCopied = copiedKey === copyKey;
    return (
        <motion.button
            whileTap={{ scale: 0.85 }}
            onClick={() => onCopy(text, label, copyKey)}
            className={clsx(
                'p-2 rounded-xl transition-all shadow-sm border',
                isCopied 
                    ? 'bg-green-500 border-green-500 text-white shadow-green-500/20' 
                    : 'bg-muted border-border text-muted-foreground hover:bg-muted/80 hover:text-foreground',
                className
            )}
            title={`Copy ${label}`}
        >
            <AnimatePresence mode="wait" initial={false}>
                {isCopied
                    ? <motion.span key="check" initial={{ scale: 0 }} animate={{ scale: 1 }} exit={{ scale: 0 }}><Check size={14} /></motion.span>
                    : <motion.span key="copy" initial={{ scale: 0 }} animate={{ scale: 1 }} exit={{ scale: 0 }}><Copy size={14} /></motion.span>
                }
            </AnimatePresence>
        </motion.button>
    );
}

export default function ItemCard({
    item,
    toggleFavorite,
    onEdit,
    onDelete,
    onShare,
    checkBreach,
    isBreached,
    breachStatus,
    breachLoading
}) {
    const { copiedKey, copy } = useCopyFeedback();
    const [totpCode, setTotpCode] = useState('');
    const [totpTimeLeft, setTotpTimeLeft] = useState(30);
    const [isFlipped, setIsFlipped] = useState(false);
    const [showCC, setShowCC] = useState(false);
    const [showPwd, setShowPwd] = useState(false);
    const [logoError, setLogoError] = useState(false);

    const type = item.itemType || 'LOGIN';

    // TOTP generation
    useEffect(() => {
        if (type !== 'LOGIN' || !item.totpSecret) return;
        let totp;
        try {
            totp = new TOTP({
                issuer: item.appName,
                label: item.username || 'user',
                algorithm: 'SHA1',
                digits: 6,
                period: 30,
                secret: item.totpSecret.replace(/\s+/g, '')
            });
        } catch (e) {
            console.error('Invalid TOTP Secret for', item.appName);
            return;
        }
        const updateTotp = () => {
            setTotpCode(totp.generate());
            const seconds = Math.floor(Date.now() / 1000);
            setTotpTimeLeft(30 - (seconds % 30));
        };
        updateTotp();
        const interval = setInterval(updateTotp, 1000);
        return () => clearInterval(interval);
    }, [type, item.totpSecret, item.appName, item.username]);

    const getDomain = () => {
        if (!item.url) return null;
        try { return new URL(item.url.startsWith('h') ? item.url : `https://${item.url}`).hostname; } 
        catch { return null; }
    };

    const domain = getDomain();

    const getIcon = () => {
        switch (type) {
            case 'CREDIT_CARD': return <CreditCard size={22} className="text-secondary" />;
            case 'IDENTITY':    return <UserCircle size={22} className="text-primary" />;
            case 'WIFI':        return <Wifi size={22} className="text-sky-400" />;
            case 'SECURE_NOTE': return <FileText size={22} className="text-orange-400" />;
            case 'FILE':        return <span className="text-2xl">📄</span>;
            default:            return <KeyRound size={22} className="text-primary" />;
        }
    };

    const renderLoginContent = () => (
        <div className="space-y-3">
