import React, { useEffect, useRef } from 'react';
import { motion } from 'framer-motion';
import { ShieldAlert } from 'lucide-react';
import useAuthStore from '../store/useAuthStore';

const LockdownAnimation = ({ onComplete }) => {
    const canvasRef = useRef(null);
    const { logout } = useAuthStore();

    useEffect(() => {
        const canvas = canvasRef.current;
        const ctx = canvas.getContext('2d');

        canvas.width = window.innerWidth;
        canvas.height = window.innerHeight;

        const katakana = 'アァカサタナハマヤャラワガザダバパイィキシチニヒミリヰギジヂビピウゥクスツヌフムユュルグズブヅプエェケセテネヘメレゲゼデベペオォコソトノホモヨョロゴゾドボポヴッン';
        const latin = 'ABCDEFGHIJKLMNOPQRSTUVWXYZ';
        const nums = '0123456789';
        const alphabet = katakana + latin + nums;

        const fontSize = 16;
        const columns = canvas.width / fontSize;
        const drops = [];
        for (let x = 0; x < columns; x++) drops[x] = 1;

        const draw = () => {
            ctx.fillStyle = 'rgba(0, 0, 0, 0.05)';
            ctx.fillRect(0, 0, canvas.width, canvas.height);

            ctx.fillStyle = '#0F0';
            ctx.font = fontSize + 'px monospace';

            for (let i = 0; i < drops.length; i++) {
                const text = alphabet.charAt(Math.floor(Math.random() * alphabet.length));
                ctx.fillText(text, i * fontSize, drops[i] * fontSize);

                if (drops[i] * fontSize > canvas.height && Math.random() > 0.975) {
                    drops[i] = 0;
                }
                drops[i]++;
            }
        };

        const interval = setInterval(draw, 30);

        // Perform actual logout logic after 2 seconds
        const timeout = setTimeout(() => {
            clearInterval(interval);
            logout();
            if (onComplete) onComplete();
        }, 2500);

        return () => {
            clearInterval(interval);
            clearTimeout(timeout);
        };
    }, [logout, onComplete]);

    return (
        <motion.div 
            initial={{ opacity: 0 }} 
            animate={{ opacity: 1 }} 
            exit={{ opacity: 0 }} 
            className="fixed inset-0 z-[9999] bg-black flex flex-col items-center justify-center overflow-hidden"
        >
            <canvas ref={canvasRef} className="absolute inset-0 opacity-40"></canvas>

            <div className="relative z-10 flex flex-col items-center text-red-500 animate-pulse">
                <ShieldAlert size={80} strokeWidth={1} className="mb-6" />
                <h1 className="text-4xl md:text-6xl font-mono font-bold tracking-[0.3em] uppercase">Emergency Lockdown</h1>
                <p className="mt-4 text-sm font-mono tracking-widest text-green-500 opacity-80">WIPING ALL DECRYPTED MEMORY...</p>
                <p className="mt-2 text-xs font-mono tracking-widest text-green-500/50">PROTOCOL ZERO INITIATED</p>
            </div>

            {/* Scanline overlay */}
            <div className="absolute inset-0 z-20 pointer-events-none bg-[linear-gradient(transparent_50%,rgba(0,0,0,0.25)_50%)] bg-[length:100%_4px]"></div>
        </motion.div>
    );
};

