                                            <div className="flex-1 min-w-0">
                                                <div className="flex items-center justify-between gap-2 mb-1">
                                                    <p className={clsx("text-sm leading-tight truncate", !n.read ? "font-bold text-foreground" : "font-medium text-foreground/80")}>
                                                        {n.title}
