export default function PasswordGenerator({ onUse, onClose }) {
  const [length, setLength] = useState(16);
  const [upper, setUpper] = useState(true);
  const [lower, setLower] = useState(true);
  const [numbers, setNumbers] = useState(true);
  const [symbols, setSymbols] = useState(true);
  const [excludeAmbiguous, setExcludeAmbiguous] = useState(false);
  const [password, setPassword] = useState('');
  const [copied, setCopied] = useState(false);

  const generate = () => {
    let charset = '';
    let lChars = 'abcdefghijklmnopqrstuvwxyz';
    let uChars = 'ABCDEFGHIJKLMNOPQRSTUVWXYZ';
    let nChars = '0123456789';
    let sChars = '!@#$%^&*()_+-=[]{}|;:,.<>?';

    if (excludeAmbiguous) {
      lChars = lChars.replace(/[ilo]/g, '');
      uChars = uChars.replace(/[ILO]/g, '');
      nChars = nChars.replace(/[01]/g, '');
      // Symbols usually don't have many ambiguous ones vs letters but sometimes | or .
    }

    if (lower) charset += lChars;
    if (upper) charset += uChars;
    if (numbers) charset += nChars;
    if (symbols) charset += sChars;

    if (!charset) return;
    let result = '';
    for (let i = 0; i < length; i++) {
      result += charset[Math.floor(Math.random() * charset.length)];
    }
    setPassword(result);
  };

  useEffect(() => { generate(); }, [length, upper, lower, numbers, symbols, excludeAmbiguous]);

  const handleCopy = () => {
    navigator.clipboard.writeText(password);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  return (
    <motion.div
      initial={{ opacity: 0 }}
      animate={{ opacity: 1 }}
      exit={{ opacity: 0 }}
      className="fixed inset-0 z-[120] flex items-center justify-center p-4 bg-background/80 backdrop-blur-md"
    >
      <motion.div
        initial={{ scale: 0.95, y: 20 }}
        animate={{ scale: 1, y: 0 }}
        exit={{ scale: 0.95, y: 20 }}
        transition={{ type: 'spring', damping: 25, stiffness: 300 }}
        className="glass-panel border border-border w-full max-w-md rounded-3xl shadow-2xl overflow-hidden relative"
      >
        <div className="absolute top-0 left-0 w-full h-1 bg-gradient-to-r from-green-500/50 via-green-400 to-green-500/50" />

        <div className="p-7">
          <div className="flex items-center justify-between mb-6">
            <div className="flex items-center gap-2">
              <Zap size={22} className="text-primary" />
              <h2 className="text-xl font-bold tracking-tight">Password Generator</h2>
            </div>
            <button onClick={onClose} className="p-2 rounded-full hover:bg-black/5 dark:hover:bg-white/5 transition-colors">
              <X size={20} />
            </button>
          </div>

          {/* Password Display */}
          <div className="bg-black/5 dark:bg-black/30 rounded-2xl p-4 flex items-center gap-3 mb-2 border border-white/5 min-h-[64px]">
            <p className="flex-1 font-mono text-base tracking-widest break-all text-foreground select-all">{password}</p>
            <div className="flex gap-1 shrink-0">
              <motion.button whileTap={{ scale: 0.85 }} onClick={generate}
                className="p-2 rounded-lg hover:bg-white/10 text-muted-foreground hover:text-foreground transition-colors" title="Regenerate">
                <RefreshCw size={17} />
              </motion.button>
              <motion.button whileTap={{ scale: 0.85 }} onClick={handleCopy}
                className="p-2 rounded-lg hover:bg-white/10 text-muted-foreground hover:text-foreground transition-colors" title="Copy">
                {copied ? <Check size={17} className="text-green-400" /> : <Copy size={17} />}
              </motion.button>
            </div>
          </div>

          {/* Strength Bar */}
          <div className="mb-4">
            <PasswordStrength password={password} />
          </div>

          {/* Length Slider */}
          <div className="mb-5 pt-2">
            <div className="flex justify-between items-center mb-2">
              <label className="text-xs font-semibold uppercase tracking-wider text-muted-foreground">Length</label>
              <span className="text-sm font-bold bg-primary/15 text-primary px-2.5 py-0.5 rounded-lg">{length}</span>
            </div>
            <input type="range" min="8" max="64" value={length}
              onChange={(e) => setLength(parseInt(e.target.value))}
              className="w-full h-2 rounded-full appearance-none cursor-pointer accent-primary bg-black/10 dark:bg-white/10" />
            <div className="flex justify-between text-xs text-muted-foreground mt-1"><span>8</span><span>64</span></div>
          </div>

          {/* Toggles */}
          <div className="flex flex-wrap gap-2 mb-7">
            <Toggle label="Uppercase" value={upper} onChange={setUpper} />
            <Toggle label="Lowercase" value={lower} onChange={setLower} />
            <Toggle label="Numbers" value={numbers} onChange={setNumbers} />
            <Toggle label="Symbols" value={symbols} onChange={setSymbols} />
            <Toggle label="No Ambi" value={excludeAmbiguous} onChange={setExcludeAmbiguous} />
          </div>

          <div className="flex gap-3">
            <motion.button whileHover={{ scale: 1.02 }} whileTap={{ scale: 0.98 }}
              onClick={handleCopy}
              className="flex-1 py-3 rounded-xl font-semibold border border-border hover:bg-black/5 dark:hover:bg-white/5 transition-colors text-sm">
              {copied ? '✓ Copied!' : 'Copy'}
            </motion.button>
            <motion.button whileHover={{ scale: 1.02 }} whileTap={{ scale: 0.98 }}
              onClick={() => onUse(password)}
              className="flex-1 py-3 rounded-xl font-bold bg-primary text-primary-foreground shadow-lg shadow-primary/25">
              Use Password
            </motion.button>
          </div>
        </div>
      </motion.div>
    </motion.div>
  );
}

import React, { useState, useEffect, useCallback } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import {
    X, Share2, Link, Copy, Check, Clock, Lock,
    Shield, Trash2, Loader2, AlertTriangle, ExternalLink,
    ChevronDown, Eye, EyeOff, RefreshCw, ShieldCheck
} from 'lucide-react';
import CryptoJS from 'crypto-js';
import { createShareLink, getMyShareLinks, revokeShareLink } from '../lib/api';
import useToastStore from '../store/useToastStore';

// ── Constants ────────────────────────────────────────────────────────────
const EXPIRY_OPTIONS = [
    { label: '1 Hour',  value: 1  },
    { label: '6 Hours', value: 6  },
    { label: '1 Day',   value: 24 },
    { label: '7 Days',  value: 168 },
];

// ── Helper: Generate random shareKey (32 random bytes as hex) ────────────
// This key NEVER leaves the browser — it travels only in URL hash (#key=...)
const generateShareKey = () => CryptoJS.lib.WordArray.random(32).toString();

// ── Helper: Encrypt item payload with shareKey ────────────────────────────
const encryptForSharing = (itemData, shareKey) => {
    try {
        // Only share relevant fields — strip internal metadata
        const payload = {
            appName: itemData.appName,
            username: itemData.username,
            password: itemData.password,
            url: itemData.url,
            note: itemData.note,
            ssid: itemData.ssid,
            cardholder: itemData.cardholder,
            cardNumber: itemData.cardNumber,
            expiry: itemData.expiry,
            cvv: itemData.cvv,
            fullName: itemData.fullName,
            idNumber: itemData.idNumber,
            dob: itemData.dob,
            itemType: itemData.itemType || 'LOGIN',
        };
        // Remove undefined fields to keep blob clean
        Object.keys(payload).forEach(k => payload[k] === undefined && delete payload[k]);
        return CryptoJS.AES.encrypt(JSON.stringify(payload), shareKey).toString();
    } catch {
        return null;
    }
};

// ── Helper: Format relative time remaining ────────────────────────────────
const timeUntil = (dateStr) => {
    const diff = new Date(dateStr).getTime() - Date.now();
    if (diff <= 0) return 'Expired';
    const h = Math.floor(diff / 3600000);
    const m = Math.floor((diff % 3600000) / 60000);
    if (h >= 24) return `${Math.floor(h / 24)}d ${h % 24}h`;
    if (h > 0) return `${h}h ${m}m`;
    return `${m}m`;
};

// ── Copy-with-feedback ────────────────────────────────────────────────────
function CopyLinkBtn({ link }) {
    const [copied, setCopied] = useState(false);
    const { addToast } = useToastStore();
    const handleCopy = () => {
        navigator.clipboard.writeText(link);
        setCopied(true);
        addToast('Secure link copied to clipboard!', 'success');
        setTimeout(() => setCopied(false), 2500);
    };
    return (
        <motion.button
            whileTap={{ scale: 0.93 }}
            onClick={handleCopy}
            className={`flex items-center gap-2 px-4 py-2.5 rounded-xl font-bold text-sm transition-all shadow-sm ${
                copied
                    ? 'bg-green-500 text-white shadow-green-500/20'
                    : 'bg-primary text-primary-foreground shadow-primary/20 hover:opacity-90'
            }`}
        >
            <AnimatePresence mode="wait" initial={false}>
                {copied
                    ? <motion.span key="c" initial={{ scale: 0 }} animate={{ scale: 1 }} exit={{ scale: 0 }} className="flex items-center gap-1.5"><Check size={14} /> Copied!</motion.span>
                    : <motion.span key="d" initial={{ scale: 0 }} animate={{ scale: 1 }} exit={{ scale: 0 }} className="flex items-center gap-1.5"><Copy size={14} /> Copy Link</motion.span>
                }
            </AnimatePresence>
        </motion.button>
    );
}

// ══════════════════════════════════════════════════════════════════════════
// Main ShareModal Component
// ══════════════════════════════════════════════════════════════════════════
export default function ShareModal({ isOpen, onClose, item }) {
    const { addToast } = useToastStore();

    // ── Tab state ─────────────────────────────────────────────────────
    const [activeTab, setActiveTab] = useState('create'); // 'create' | 'links'

    // ── Create-link form state ─────────────────────────────────────────
    const [expiresInHours, setExpiresInHours] = useState(24);
    const [enablePin, setEnablePin] = useState(false);
    const [pin, setPin] = useState('');
    const [showPin, setShowPin] = useState(false);
    const [isCreating, setIsCreating] = useState(false);
    const [generatedLink, setGeneratedLink] = useState(null); // Full link with hash

    // ── My links state ────────────────────────────────────────────────
    const [myLinks, setMyLinks] = useState([]);
    const [linksLoading, setLinksLoading] = useState(false);
    const [revokingToken, setRevokingToken] = useState(null);

    // ── Reset state when modal opens/closes ───────────────────────────
    useEffect(() => {
        if (isOpen) {
            setActiveTab('create');
            setExpiresInHours(24);
            setEnablePin(false);
            setPin('');
            setShowPin(false);
            setGeneratedLink(null);
            setIsCreating(false);
        }
    }, [isOpen]);

    // ── Load active links when tab switches to 'links' ────────────────
    useEffect(() => {
        if (activeTab === 'links' && isOpen) {
            loadMyLinks();
        }
    }, [activeTab, isOpen]);

    const loadMyLinks = async () => {
        setLinksLoading(true);
        try {
            const data = await getMyShareLinks();
            setMyLinks(data);
        } catch {
            addToast('Failed to load active links', 'error');
        } finally {
            setLinksLoading(false);
        }
    };

    // ── Create share link handler ─────────────────────────────────────
    const handleCreate = useCallback(async () => {
        if (!item) return;

        // Validate PIN if enabled
        if (enablePin) {
            const trimmed = pin.trim();
            if (!/^\d{4,8}$/.test(trimmed)) {
                addToast('PIN must be 4-8 digits', 'error');
                return;
            }
        }

        setIsCreating(true);
        try {
            // 1. Generate a random share key (never sent to server)
            const shareKey = generateShareKey();

            // 2. Encrypt the item payload with the share key
            const encryptedShareBlob = encryptForSharing(item, shareKey);
            if (!encryptedShareBlob) {
                throw new Error('Encryption failed. Please try again.');
            }

            // 3. Send encrypted blob to server — get back a token
            const response = await createShareLink(
                encryptedShareBlob,
                enablePin ? pin.trim() : null,
                expiresInHours,
                item.appName || 'Shared Item'
            );

            // 4. Build full share link — shareKey goes in URL hash ONLY
            //    The hash (#) is NEVER sent to the server by browsers
            const origin = window.location.origin;
            const fullLink = `${origin}/share/${response.token}#key=${shareKey}`;
            setGeneratedLink(fullLink);

            addToast('Secure share link created!', 'success');
        } catch (err) {
            addToast(err.message || 'Failed to create share link', 'error');
        } finally {
            setIsCreating(false);
        }
    }, [item, enablePin, pin, expiresInHours, addToast]);

    // ── Revoke a link ─────────────────────────────────────────────────
    const handleRevoke = async (token) => {
        setRevokingToken(token);
        try {
            await revokeShareLink(token);
            setMyLinks(prev => prev.filter(l => l.token !== token));
            addToast('Share link revoked', 'success');
        } catch (err) {
            addToast(err.message || 'Failed to revoke link', 'error');
        } finally {
            setRevokingToken(null);
        }
    };

    // ── Close on Escape key ───────────────────────────────────────────
    useEffect(() => {
        const handler = (e) => { if (e.key === 'Escape' && isOpen) onClose(); };
        window.addEventListener('keydown', handler);
        return () => window.removeEventListener('keydown', handler);
    }, [isOpen, onClose]);

    // ══════════════════════════════════════════════════════════════════
    // Render
    // ══════════════════════════════════════════════════════════════════
    return (
        <AnimatePresence>
            {isOpen && (
                <>
                    {/* Backdrop */}
                    <motion.div
                        key="share-backdrop"
                        initial={{ opacity: 0 }}
                        animate={{ opacity: 1 }}
                        exit={{ opacity: 0 }}
                        onClick={onClose}
                        className="fixed inset-0 bg-black/60 backdrop-blur-sm z-50"
                    />

                    {/* Modal */}
                    <motion.div
                        key="share-modal"
                        initial={{ opacity: 0, scale: 0.94, y: 20 }}
                        animate={{ opacity: 1, scale: 1, y: 0 }}
                        exit={{ opacity: 0, scale: 0.94, y: 20 }}
                        transition={{ type: 'spring', stiffness: 380, damping: 28 }}
                        className="fixed inset-0 z-50 flex items-center justify-center p-4 pointer-events-none"
                    >
                        <div
                            className="glass-panel border border-border rounded-3xl shadow-2xl w-full max-w-md pointer-events-auto overflow-hidden"
                            onClick={e => e.stopPropagation()}
                        >
                            {/* ── Modal Header ─────────────────────── */}
                            <div className="flex items-center justify-between px-6 pt-6 pb-4 border-b border-border/50">
                                <div className="flex items-center gap-3">
                                    <div className="w-9 h-9 rounded-xl bg-primary/10 flex items-center justify-center text-primary border border-primary/20">
                                        <Share2 size={16} />
                                    </div>
                                    <div>
                                        <h2 className="font-bold text-base">Secure Share</h2>
                                        <p className="text-[10px] text-muted-foreground font-bold uppercase tracking-widest">
                                            {item?.appName || 'Vault Item'}
                                        </p>
                                    </div>
                                </div>
                                <button
                                    id="share-modal-close"
                                    onClick={onClose}
                                    className="p-2 rounded-xl text-muted-foreground hover:text-foreground hover:bg-black/5 dark:hover:bg-white/5 transition-colors"
                                >
                                    <X size={18} />
                                </button>
                            </div>

                            {/* ── Tabs ─────────────────────────────── */}
                            <div className="flex border-b border-border/50 px-6">
                                {[
                                    { id: 'create', label: 'Create Link' },
                                    { id: 'links',  label: 'Active Links' }
                                ].map(tab => (
                                    <button
                                        key={tab.id}
                                        id={`share-tab-${tab.id}`}
                                        onClick={() => setActiveTab(tab.id)}
                                        className={`px-4 py-3 text-sm font-bold border-b-2 transition-colors ${
                                            activeTab === tab.id
                                                ? 'border-primary text-primary'
                                                : 'border-transparent text-muted-foreground hover:text-foreground'
                                        }`}
                                    >
                                        {tab.label}
                                    </button>
                                ))}
                            </div>

                            {/* ── Tab Content ──────────────────────── */}
                            <AnimatePresence mode="wait">

                                {/* ─ CREATE TAB ────────────────────── */}
                                {activeTab === 'create' && (
                                    <motion.div
                                        key="create-tab"
                                        initial={{ opacity: 0, x: -10 }}
                                        animate={{ opacity: 1, x: 0 }}
                                        exit={{ opacity: 0, x: 10 }}
                                        className="p-6 space-y-5"
                                    >
                                        {!generatedLink ? (
                                            <>
                                                {/* Zero-knowledge notice */}
                                                <div className="flex items-start gap-3 p-3.5 bg-primary/5 border border-primary/20 rounded-2xl text-xs">
                                                    <ShieldCheck size={14} className="text-primary shrink-0 mt-0.5" />
                                                    <p className="text-muted-foreground leading-relaxed">
                                                        <span className="font-bold text-foreground">Zero-Knowledge sharing.</span> The decryption key travels only in the URL — KeeperX server never sees it.
                                                    </p>
                                                </div>

                                                {/* Expiry selector */}
                                                <div>
                                                    <label className="text-xs font-bold uppercase tracking-widest text-muted-foreground mb-2 flex items-center gap-1.5">
                                                        <Clock size={11} /> Expires After
                                                    </label>
                                                    <div className="grid grid-cols-4 gap-2">
                                                        {EXPIRY_OPTIONS.map(opt => (
                                                            <button
                                                                key={opt.value}
                                                                id={`share-expiry-${opt.value}`}
                                                                onClick={() => setExpiresInHours(opt.value)}
                                                                className={`py-2.5 rounded-xl text-xs font-bold border transition-all ${
                                                                    expiresInHours === opt.value
                                                                        ? 'bg-primary text-primary-foreground border-primary shadow-sm shadow-primary/20'
                                                                        : 'bg-black/5 dark:bg-white/5 border-border text-muted-foreground hover:text-foreground'
                                                                }`}
                                                            >
                                                                {opt.label}
                                                            </button>
                                                        ))}
                                                    </div>
                                                </div>

                                                {/* PIN toggle */}
                                                <div>
                                                    <div className="flex items-center justify-between mb-2">
                                                        <label className="text-xs font-bold uppercase tracking-widest text-muted-foreground flex items-center gap-1.5">
                                                            <Lock size={11} /> PIN Protection
                                                        </label>
                                                        <button
                                                            id="share-pin-toggle"
                                                            onClick={() => { setEnablePin(p => !p); setPin(''); }}
                                                            className={`w-11 h-6 rounded-full border transition-all relative ${
                                                                enablePin
                                                                    ? 'bg-primary border-primary'
                                                                    : 'bg-black/10 dark:bg-white/10 border-border'
                                                            }`}
                                                        >
                                                            <span className={`absolute top-0.5 w-5 h-5 rounded-full bg-white shadow transition-all ${enablePin ? 'left-[22px]' : 'left-0.5'}`} />
                                                        </button>
                                                    </div>
                                                    <AnimatePresence>
                                                        {enablePin && (
                                                            <motion.div
                                                                initial={{ opacity: 0, height: 0 }}
                                                                animate={{ opacity: 1, height: 'auto' }}
                                                                exit={{ opacity: 0, height: 0 }}
                                                                className="overflow-hidden"
                                                            >
                                                                <div className="relative">
                                                                    <input
                                                                        id="share-pin-input"
                                                                        type={showPin ? 'text' : 'password'}
                                                                        inputMode="numeric"
                                                                        value={pin}
                                                                        onChange={e => setPin(e.target.value.replace(/\D/g, '').slice(0, 8))}
                                                                        placeholder="Enter 4–8 digit PIN"
                                                                        className="w-full bg-black/5 dark:bg-white/5 border border-border rounded-xl px-4 py-2.5 text-sm font-mono tracking-widest focus:outline-none focus:ring-2 focus:ring-primary/40 focus:border-primary/50 transition-all pr-10"
                                                                    />
                                                                    <button
                                                                        type="button"
                                                                        onClick={() => setShowPin(p => !p)}
                                                                        className="absolute right-3 top-1/2 -translate-y-1/2 text-muted-foreground hover:text-foreground transition-colors"
                                                                    >
                                                                        {showPin ? <EyeOff size={14} /> : <Eye size={14} />}
                                                                    </button>
                                                                </div>
                                                            </motion.div>
                                                        )}
                                                    </AnimatePresence>
                                                </div>

                                                {/* Generate button */}
                                                <motion.button
                                                    id="share-generate-btn"
                                                    whileTap={{ scale: 0.97 }}
                                                    onClick={handleCreate}
                                                    disabled={isCreating || (enablePin && pin.length < 4)}
                                                    className="w-full bg-primary text-primary-foreground py-3 rounded-xl font-bold flex items-center justify-center gap-2 shadow-lg shadow-primary/20 disabled:opacity-50 disabled:cursor-not-allowed transition-all hover:opacity-90"
                                                >
                                                    {isCreating
                                                        ? <><Loader2 size={16} className="animate-spin" /> Generating…</>
                                                        : <><Link size={16} /> Generate Secure Link</>
                                                    }
                                                </motion.button>
                                            </>
                                        ) : (
                                            /* ─ SUCCESS: Link Generated ─ */
                                            <motion.div
                                                initial={{ opacity: 0, y: 10 }}
                                                animate={{ opacity: 1, y: 0 }}
                                                className="space-y-4"
                                            >
                                                {/* Success badge */}
                                                <div className="flex items-center gap-2 justify-center py-2">
                                                    <div className="w-8 h-8 bg-green-500/10 rounded-xl flex items-center justify-center">
                                                        <Shield size={16} className="text-green-500" />
                                                    </div>
                                                    <span className="font-bold text-green-500 text-sm">Secure link ready!</span>
                                                </div>

                                                {/* Link display */}
                                                <div className="p-3 bg-black/5 dark:bg-white/5 border border-border/50 rounded-2xl">
                                                    <p className="text-[10px] font-bold uppercase tracking-widest text-muted-foreground mb-1.5">Your Secure Link</p>
                                                    <p className="text-xs font-mono text-muted-foreground break-all leading-relaxed line-clamp-3 mb-3">
                                                        {generatedLink}
                                                    </p>
                                                    <div className="flex gap-2">
                                                        <CopyLinkBtn link={generatedLink} />
                                                        <a
                                                            href={generatedLink}
                                                            target="_blank"
                                                            rel="noreferrer"
                                                            className="flex items-center gap-1.5 px-3 py-2.5 rounded-xl text-xs font-bold text-muted-foreground hover:text-foreground border border-border hover:bg-black/5 dark:hover:bg-white/5 transition-all"
                                                        >
                                                            <ExternalLink size={12} /> Preview
                                                        </a>
                                                    </div>
                                                </div>

                                                {/* Warnings */}
                                                <div className="space-y-2">
                                                    <div className="flex items-start gap-2 p-3 bg-amber-500/10 border border-amber-500/20 rounded-xl text-xs">
                                                        <AlertTriangle size={12} className="text-amber-500 shrink-0 mt-0.5" />
                                                        <p className="text-muted-foreground">
                                                            <span className="font-bold text-foreground">One-time use only.</span> The link self-destructs after first access.
                                                        </p>
                                                    </div>
                                                    {enablePin && (
                                                        <div className="flex items-start gap-2 p-3 bg-primary/5 border border-primary/20 rounded-xl text-xs">
                                                            <Lock size={12} className="text-primary shrink-0 mt-0.5" />
                                                            <p className="text-muted-foreground">
                                                                <span className="font-bold text-foreground">PIN protected.</span> Share your PIN <span className="italic">separately</span> (e.g., via call) — not in the same message as the link.
                                                            </p>
                                                        </div>
                                                    )}
                                                </div>

                                                {/* Create another */}
                                                <button
                                                    id="share-create-another"
                                                    onClick={() => { setGeneratedLink(null); setPin(''); setEnablePin(false); }}
                                                    className="w-full flex items-center justify-center gap-2 text-sm font-bold text-muted-foreground hover:text-foreground py-2 transition-colors"
                                                >
                                                    <RefreshCw size={13} /> Create Another Link
                                                </button>
                                            </motion.div>
                                        )}
                                    </motion.div>
                                )}

                                {/* ─ ACTIVE LINKS TAB ──────────────── */}
                                {activeTab === 'links' && (
                                    <motion.div
                                        key="links-tab"
                                        initial={{ opacity: 0, x: 10 }}
                                        animate={{ opacity: 1, x: 0 }}
                                        exit={{ opacity: 0, x: -10 }}
                                        className="p-6"
                                    >
                                        <div className="flex items-center justify-between mb-4">
                                            <p className="text-xs font-bold uppercase tracking-widest text-muted-foreground">
                                                All Active Share Links
                                            </p>
                                            <button
                                                id="share-links-refresh"
                                                onClick={loadMyLinks}
                                                disabled={linksLoading}
                                                className="p-1.5 rounded-lg text-muted-foreground hover:text-foreground hover:bg-black/5 dark:hover:bg-white/5 transition-colors"
                                                title="Refresh"
                                            >
                                                <RefreshCw size={13} className={linksLoading ? 'animate-spin' : ''} />
                                            </button>
                                        </div>

                                        {linksLoading ? (
                                            <div className="flex items-center justify-center py-10">
                                                <Loader2 size={20} className="animate-spin text-primary" />
                                            </div>
                                        ) : myLinks.length === 0 ? (
                                            <div className="text-center py-10">
                                                <Share2 size={28} className="mx-auto text-muted-foreground/40 mb-3" />
                                                <p className="text-sm font-bold text-muted-foreground">No active share links</p>
                                                <p className="text-xs text-muted-foreground/60 mt-1">Links you create will appear here</p>
                                            </div>
                                        ) : (
                                            <div className="space-y-2.5 max-h-72 overflow-y-auto custom-scrollbar pr-1">
                                                {myLinks.map(link => (
                                                    <motion.div
                                                        key={link.token}
                                                        layout
                                                        initial={{ opacity: 0, y: 5 }}
                                                        animate={{ opacity: 1, y: 0 }}
                                                        exit={{ opacity: 0, x: -10 }}
                                                        className={`p-3.5 rounded-2xl border transition-all ${
                                                            link.isUsed
                                                                ? 'bg-black/5 dark:bg-white/5 border-border/30 opacity-50'
                                                                : 'bg-primary/5 border-primary/20'
                                                        }`}
                                                    >
                                                        <div className="flex items-start justify-between gap-2">
                                                            <div className="min-w-0 flex-1">
                                                                <div className="flex items-center gap-1.5 mb-1">
                                                                    <p className="text-sm font-bold truncate">{link.itemLabel}</p>
                                                                    {link.hasPinProtection && (
                                                                        <span className="shrink-0 flex items-center gap-0.5 text-[8px] font-black uppercase tracking-wider px-1.5 py-0.5 rounded-full bg-primary/10 text-primary border border-primary/20">
                                                                            <Lock size={7} /> PIN
                                                                        </span>
                                                                    )}
                                                                    {link.isUsed && (
                                                                        <span className="shrink-0 text-[8px] font-black uppercase tracking-wider px-1.5 py-0.5 rounded-full bg-green-500/10 text-green-500 border border-green-500/20">
                                                                            Used
                                                                        </span>
                                                                    )}
                                                                </div>
                                                                <div className="flex items-center gap-2 text-[10px] text-muted-foreground">
                                                                    <Clock size={9} />
                                                                    <span>Expires in {timeUntil(link.expiresAt)}</span>
                                                                    {link.accessLog?.accessedAt && (
                                                                        <span className="text-green-500 font-bold">· Accessed</span>
                                                                    )}
                                                                </div>
                                                            </div>
                                                            <button
                                                                id={`share-revoke-${link.token?.slice(0, 8)}`}
                                                                onClick={() => handleRevoke(link.token)}
                                                                disabled={revokingToken === link.token}
                                                                className="shrink-0 p-1.5 rounded-lg text-red-400 hover:text-red-500 hover:bg-red-500/10 transition-colors disabled:opacity-40"
                                                                title="Revoke link"
                                                            >
                                                                {revokingToken === link.token
                                                                    ? <Loader2 size={13} className="animate-spin" />
                                                                    : <Trash2 size={13} />
                                                                }
                                                            </button>
                                                        </div>
                                                    </motion.div>
                                                ))}
                                            </div>
                                        )}
                                    </motion.div>
                                )}

                            </AnimatePresence>
                        </div>
                    </motion.div>
                </>
            )}
        </AnimatePresence>
    );
}

import React, { useState, useEffect } from 'react';
import { NavLink, useNavigate } from 'react-router-dom';
import {
    Shield, LayoutDashboard, ShieldCheck, Radar,
    Bot, Trash2, Settings, LogOut, Star, Lock,
    ChevronLeft, ChevronRight, X, Users, HelpCircle, ShieldAlert,
    HardDrive
} from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';
import { logoutUser, fetchVaultItems } from '../lib/api';
import useAuthStore from '../store/useAuthStore';
import useToastStore from '../store/useToastStore';
import clsx from 'clsx';

const navItems = [
    { to: '/',         Icon: LayoutDashboard, label: 'Vault',         badge: 'total' },
    { to: '/audit',    Icon: ShieldCheck,      label: 'Security Audit' },
    { to: '/scanner',  Icon: Radar,            label: 'Breach Scanner' },
    { to: '/phishing', Icon: Bot,              label: 'AI Analyzer' },
    { to: '/locker',   Icon: HardDrive,        label: 'Document Locker' },
    { to: '/trash',     Icon: Trash2,        label: 'Trash',            badge: 'trash', danger: true },
    { to: '/emergency', Icon: ShieldAlert,    label: 'Emergency Access' },
    { to: '/support',   Icon: HelpCircle,    label: 'Support Tickets' },
    { to: '/settings',  Icon: Settings,      label: 'Settings' },
];

export default function Sidebar({ isOpen, onClose }) {
    const navigate = useNavigate();
    const { user, lockVault, logout } = useAuthStore();
    const { addToast } = useToastStore();
    const [isCollapsed, setIsCollapsed] = useState(false);
    const [trashCount, setTrashCount] = useState(0);
    const [totalCount, setTotalCount] = useState(0);

    // Load item counts for badges
    useEffect(() => {
        const loadCounts = async () => {
            try {
                const items = await fetchVaultItems();
                setTrashCount(items.filter(i => i.isDeleted).length);
                setTotalCount(items.filter(i => !i.isDeleted).length);
            } catch { /* silent */ }
        };
        loadCounts();
        const interval = setInterval(loadCounts, 30000);
        return () => clearInterval(interval);
    }, []);

    const handleLogout = async () => {
        try {
            await logoutUser();
            logout();
            navigate('/login');
        } catch {
            addToast('Logout failed', 'error');
        }
    };

    const handleLock = () => {
        lockVault();
        addToast('Vault locked', 'info');
    };

    const getBadgeValue = (badge) => {
        if (badge === 'trash') return trashCount > 0 ? trashCount : null;
        if (badge === 'total') return totalCount > 0 ? totalCount : null;
        return null;
    };

    const sidebarInner = (
        <div className="flex flex-col h-full">
            {/* Brand */}
            <div className={clsx('px-5 py-5 border-b border-border/50 shrink-0 flex items-center gap-3', isCollapsed && 'justify-center px-3')}>
                <div className="relative shrink-0">
                    <div className="w-9 h-9 rounded-xl bg-gradient-to-br from-primary to-secondary flex items-center justify-center shadow-lg text-white shrink-0">
                        <Shield size={18} />
                    </div>
                    <span className="absolute -top-1 -right-1 w-2.5 h-2.5 bg-green-500 rounded-full border-2 border-background animate-pulse" />
                </div>
                {!isCollapsed && (
                    <div className="min-w-0">
                        <span className="font-extrabold text-base tracking-tight leading-none block">Keeper<span className="text-primary">X</span></span>
                        <span className="text-[9px] font-bold uppercase tracking-widest text-muted-foreground/80 mt-1 block">Enterprise Vault</span>
                    </div>
                )}
            </div>

            {/* Nav */}
            <div className="flex-1 overflow-y-auto no-scrollbar py-4 px-3 space-y-1">
                {navItems.map(({ to, Icon, label, badge, danger }) => {
                    const badgeVal = badge ? getBadgeValue(badge) : null;
                    return (
                        <NavLink
                            key={to}
                            to={to}
                            end={to === '/'}
                            onClick={onClose}
                            className={({ isActive }) => clsx(
                                'flex items-center gap-3 font-semibold text-sm rounded-xl transition-all relative group',
                                isCollapsed ? 'justify-center p-2.5' : 'px-3 py-2.5',
                                isActive
                                    ? 'bg-primary/10 text-primary border border-primary/10'
                                    : danger
                                        ? 'text-muted-foreground hover:text-red-500 hover:bg-red-500/5'
                                        : 'text-muted-foreground hover:text-foreground hover:bg-muted/50'
                            )}
                        >
                            <Icon size={18} className={clsx('shrink-0', isCollapsed ? 'opacity-100' : 'opacity-80 group-hover:opacity-100')} />
                            {!isCollapsed && <span className="flex-1 truncate">{label}</span>}

                            {/* Active Indicator bar */}
                            <NavLink to={to} end={to === '/'} className={({ isActive }) => clsx(
                                "absolute left-0 w-1 bg-primary rounded-full transition-all duration-300",
                                isActive ? "h-6" : "h-0"
                            )} />

                            {badgeVal != null && !isCollapsed && (
                                <span className={clsx(
                                    'text-[10px] font-black px-1.5 py-0.5 rounded-md leading-none',
                                    badge === 'trash'
                                        ? 'bg-red-500/10 text-red-500 border border-red-500/10'
                                        : 'bg-primary/10 text-primary border border-primary/10'
                                )}>
                                    {badgeVal}
                                </span>
                            )}
                            {isCollapsed && badgeVal != null && (
                                <span className="absolute top-1.5 right-1.5 w-2 h-2 bg-red-500 rounded-full border-2 border-background" />
                            )}
                            {/* Tooltip for collapsed sidebar */}
                            {isCollapsed && (
                                <span className="absolute left-full ml-3 px-3 py-2 bg-surface-1 border border-border rounded-xl text-xs font-bold opacity-0 group-hover:opacity-100 transition-all whitespace-nowrap shadow- premium pointer-events-none z-50">
                                    {label}{badgeVal != null ? ` (${badgeVal})` : ''}
                                </span>
                            )}
                        </NavLink>
                    );
                })}

                {(user?.role === 'admin' || user?.role === 'superadmin') && (
                    <NavLink
                        to="/admin/dashboard"
                        onClick={onClose}
                        className={({ isActive }) => clsx(
                            'flex items-center gap-3 font-bold text-sm rounded-xl transition-all relative group mt-6',
                            isCollapsed ? 'justify-center p-2.5' : 'px-3 py-2.5',
                            isActive
                                ? 'bg-primary/10 text-primary border border-primary/20'
                                : 'text-primary/80 hover:text-primary hover:bg-primary/5 border border-primary/10'
                        )}
                    >
                        <Users size={18} className="shrink-0" />
                        {!isCollapsed && <span className="flex-1 truncate">Admin Dashboard</span>}
                        {isCollapsed && (
                            <span className="absolute left-full ml-3 px-3 py-2 bg-surface-1 border border-border rounded-xl text-xs font-bold opacity-0 group-hover:opacity-100 transition-all whitespace-nowrap shadow-premium pointer-events-none z-50">
                                Admin Dashboard
                            </span>
                        )}
                    </NavLink>
                )}
            </div>

            {/* Footer */}
            <div className={clsx('p-3 border-t border-border/50 shrink-0 space-y-1', isCollapsed && 'px-2')}>
                {/* User */}
                {!isCollapsed && (
                    <div className="flex items-center gap-2.5 p-2.5 rounded-xl mb-1">
                        <div className="w-8 h-8 rounded-xl bg-gradient-to-br from-primary to-secondary text-white flex items-center justify-center text-sm font-bold shadow-sm shrink-0">
                            {(user?.name || user?.email)?.charAt(0).toUpperCase()}
