                                        <p className="text-2xl font-black text-green-500">{selectedUser.securityStats?.strongPasswords || 0}</p>
                                        <p className="text-[9px] font-bold uppercase tracking-widest text-muted-foreground mt-0.5">Strong Passwords</p>
