                <div>
                    <h1 className="text-3xl sm:text-4xl font-black tracking-tight text-foreground mb-1">Vault Overview</h1>
                    <p className="text-muted-foreground text-sm font-medium">
                        {stats.total} item{stats.total !== 1 ? 's' : ''} encrypted with AES-256 · Press <kbd className="px-2 py-1 rounded-lg bg-muted border border-border text-[10px] font-mono shadow-sm">Ctrl+N</kbd>
                    </p>
                </div>
                <div className="flex flex-wrap items-center gap-3">
                    <AutoLockTimerDisplay />
                    <div className="relative flex-1 sm:flex-initial min-w-[180px] sm:w-64 group">
