                        />
                        {rawSearch && (
                            <button onClick={() => setRawSearch('')} className="absolute right-3 top-1/2 -translate-y-1/2 text-muted-foreground hover:text-foreground">
                                <X size={14} />
                            </button>
                        )}
                    </div>
                    <motion.button
                        whileHover={{ y: -2 }} whileTap={{ scale: 0.98 }}
