                    ))}
                </div>
            </div>

            {/* ─ AI Vault Hygiene Dashboard ───────────────────── */}
            {!loading && <VaultHygiene items={items} />}

            {/* ─ Vault Content ─────────────────────────────────── */}
            {loading ? (
                <SkeletonGrid count={6} />
