                </motion.div>
            ) : (
                <motion.div
                    variants={staggerContainer}
                    initial="hidden"
                    animate="show"
                    className="grid grid-cols-1 lg:grid-cols-2 2xl:grid-cols-3 gap-5 sm:gap-6"
                >
                    {filteredItems.map(item => (
                        <ItemCard
                            key={item._id}
                            item={item}
                            toggleFavorite={toggleFavorite}
                            onEdit={(editingItem) => {
                                setEditingItem(editingItem);
