import React, { useState, useEffect, useCallback } from 'react';
import { useParams } from 'react-router-dom';
import { motion, AnimatePresence } from 'framer-motion';
import {
    Shield, ShieldOff, ShieldCheck, Clock, Loader2, AlertTriangle,
    CheckCircle2, Key, Eye, EyeOff, Copy, Check,
    RefreshCw, KeyRound, Lock, FileText, CreditCard, Wifi, UserCircle
} from 'lucide-react';
import { requestEmergencyAccess, getEmergencyVaultAccess } from '../lib/api';
import { loadPrivateKey, hasPrivateKey, decryptWithPrivateKey } from '../lib/cryptoUtils';
import CryptoJS from 'crypto-js';

// ── Phase states ──────────────────────────────────────────────────────────
const PHASE = {
    CHECKING_KEY: 'checking_key',
    NO_KEY: 'no_key',
    READY_TO_REQUEST: 'ready_to_request',
    REQUESTING: 'requesting',
    WAITING: 'waiting',
    LOADING_VAULT: 'loading_vault',
    NEED_MASTER: 'need_master',
    VAULT_READY: 'vault_ready',
    ACCESS_DENIED: 'access_denied',
    ERROR: 'error'
};

// ── Item type icon ─────────────────────────────────────────────────────────
const TypeIcon = ({ type }) => {
    switch (type) {
        case 'CREDIT_CARD': return <CreditCard size={16} className="text-purple-400" />;
        case 'IDENTITY':    return <UserCircle size={16} className="text-blue-400" />;
        case 'WIFI':        return <Wifi size={16} className="text-sky-400" />;
        case 'SECURE_NOTE': return <FileText size={16} className="text-orange-400" />;
        default:            return <KeyRound size={16} className="text-emerald-400" />;
    }
};

// ── Copy button ────────────────────────────────────────────────────────────
function CopyBtn({ text }) {
    const [copied, setCopied] = useState(false);
    return (
        <button onClick={() => { navigator.clipboard.writeText(text); setCopied(true); setTimeout(() => setCopied(false), 2000); }}
            className={`p-1.5 rounded-lg transition-all text-xs ${copied ? 'bg-green-500 text-white' : 'bg-white/10 hover:bg-white/20 text-white/60'}`}>
            {copied ? <Check size={13} /> : <Copy size={13} />}
        </button>
    );
}

// ── Countdown timer ───────────────────────────────────────────────────────
function Countdown({ deadline }) {
    const [remaining, setRemaining] = useState('');
    useEffect(() => {
        const update = () => {
            const diff = new Date(deadline).getTime() - Date.now();
            if (diff <= 0) { setRemaining('Window passed'); return; }
            const h = Math.floor(diff / 3600000);
            const m = Math.floor((diff % 3600000) / 60000);
            const s = Math.floor((diff % 60000) / 1000);
            setRemaining(`${h}h ${m}m ${s}s`);
        };
        update();
        const t = setInterval(update, 1000);
        return () => clearInterval(t);
    }, [deadline]);
    return <span className="font-mono font-bold text-amber-300">{remaining}</span>;
}

// ══════════════════════════════════════════════════════════════════════════
export default function EmergencyVaultView() {
    const { contactId } = useParams();

    const [phase, setPhase] = useState(PHASE.CHECKING_KEY);
    const [errorMsg, setErrorMsg] = useState('');
    const [approvalDeadline, setApprovalDeadline] = useState(null);
    const [ownerName, setOwnerName] = useState('');

    // ── Vault state ───────────────────────────────────────────────────
    const [vaultBundle, setVaultBundle] = useState(null); // raw encrypted items from server
    const [encMasterKeyBundle, setEncMasterKeyBundle] = useState(null); // RSA bundle
    const [masterPassword, setMasterPassword] = useState('');
    const [showMaster, setShowMaster] = useState(false);
    const [decryptedItems, setDecryptedItems] = useState([]);
    const [decryptError, setDecryptError] = useState('');
    const [showPasswords, setShowPasswords] = useState({});

    // ── Check if private key exists in this browser ───────────────────
    useEffect(() => {
        if (!contactId) {
            setPhase(PHASE.ERROR);
            setErrorMsg('Invalid contact ID in URL');
            return;
        }
        const hasKey = hasPrivateKey(contactId);
        if (!hasKey) {
            setPhase(PHASE.NO_KEY);
        } else {
            // Key exists — try to get vault access
            fetchVaultAccess();
        }
    }, [contactId]); // eslint-disable-line

    // ── Request emergency access ──────────────────────────────────────
    const handleRequestAccess = useCallback(async () => {
        setPhase(PHASE.REQUESTING);
        try {
            const result = await requestEmergencyAccess(contactId);
            if (result.accessApprovalDeadline) {
                setApprovalDeadline(result.accessApprovalDeadline);
                setPhase(PHASE.WAITING);
            } else if (result.status === 409) {
                // Already requested
                fetchVaultAccess();
            } else {
                fetchVaultAccess();
            }
        } catch (err) {
            setPhase(PHASE.ERROR);
            setErrorMsg(err.message);
        }
    }, [contactId]); // eslint-disable-line

    // ── Poll / fetch vault access ─────────────────────────────────────
    const fetchVaultAccess = useCallback(async () => {
        setPhase(PHASE.LOADING_VAULT);
        try {
            const result = await getEmergencyVaultAccess(contactId);

            if (result.httpStatus === 202) {
                // Still in approval window
                setApprovalDeadline(result.accessApprovalDeadline);
                setPhase(PHASE.WAITING);
                return;
            }

            if (result.encryptedVaultBlob) {
                setOwnerName(result.ownerName || 'the owner');
                setVaultBundle(result.encryptedVaultBlob);
                setEncMasterKeyBundle(result.encryptedMasterKeyBundle || null);
                setPhase(PHASE.NEED_MASTER);
            } else {
                setPhase(PHASE.READY_TO_REQUEST);
            }
        } catch (err) {
            if (err.message?.includes('denied')) {
                setPhase(PHASE.ACCESS_DENIED);
            } else if (err.message?.includes('access request') || err.message?.includes('Please request')) {
                // Contact hasn't requested access yet — show "Request Access" button
                setPhase(PHASE.READY_TO_REQUEST);
            } else {
                setPhase(PHASE.ERROR);
                setErrorMsg(err.message);
            }
        }
    }, [contactId]); // eslint-disable-line

    // ── Decrypt vault items with master password ──────────────────────
    const handleDecrypt = useCallback(async (manualPassword = null) => {
        const passwordToUse = manualPassword || masterPassword;
        if (!passwordToUse || !vaultBundle) return;
        setDecryptError('');

        try {
            const bundle = JSON.parse(vaultBundle);
            const items = bundle.items || [];

            const decrypted = items.map(item => {
                try {
                    const bytes = CryptoJS.AES.decrypt(item.encryptedData, passwordToUse);
                    const text = bytes.toString(CryptoJS.enc.Utf8);
                    if (!text) return null;
                    return { id: item.id, ...JSON.parse(text) };
                } catch {
                    return null;
                }
            }).filter(Boolean);

            if (decrypted.length === 0 && items.length > 0) {
                setDecryptError(manualPassword ? 'Incorrect master password.' : 'Decryption failed. RSA key or password may be incorrect.');
                return;
            }

            setDecryptedItems(decrypted);
            setPhase(PHASE.VAULT_READY);
        } catch {
            setDecryptError('Failed to parse vault data.');
        }
    }, [masterPassword, vaultBundle]);

    // ── Attempt RSA Decryption automatically ──────────────────────────
    const attemptRSADecrypt = useCallback(async () => {
        if (!encMasterKeyBundle || !contactId || phase !== PHASE.NEED_MASTER) return;

        try {
            const privateKey = loadPrivateKey(contactId);
            if (!privateKey) return;

            // Decrypt the master key using RSA private key
            const decryptedMasterKey = await decryptWithPrivateKey(encMasterKeyBundle, privateKey);

            if (decryptedMasterKey) {
                // Success! Use this key to decrypt the rest of the vault
                handleDecrypt(decryptedMasterKey);
            }
        } catch (err) {
            console.error('RSA Decryption failed:', err);
        }
    }, [encMasterKeyBundle, contactId, phase, handleDecrypt]);

    useEffect(() => {
        if (phase === PHASE.NEED_MASTER && encMasterKeyBundle) {
            attemptRSADecrypt();
        }
    }, [phase, encMasterKeyBundle, attemptRSADecrypt]);

    // ══════════════════════════════════════════════════════════════════
    return (
        <div className="min-h-screen bg-gradient-to-br from-[#0d0f1a] via-[#111827] to-[#0d0f1a] p-4">
            <div className="max-w-2xl mx-auto">

                {/* Brand */}
                <motion.div initial={{ opacity: 0, y: -20 }} animate={{ opacity: 1, y: 0 }}
                    className="flex items-center justify-center gap-3 my-8">
                    <div className="w-10 h-10 rounded-xl bg-gradient-to-br from-violet-500 to-indigo-600 flex items-center justify-center shadow-lg shadow-violet-500/30">
                        <Shield size={20} className="text-white" />
                    </div>
                    <div>
                        <span className="font-black text-xl tracking-tight text-white">Keeper<span className="text-violet-400">X</span></span>
                        <p className="text-[10px] font-bold uppercase tracking-widest text-white/40">Emergency Vault Access</p>
                    </div>
                </motion.div>

                <AnimatePresence mode="wait">

                    {/* ── Checking / Loading ─────────────────────────── */}
                    {(phase === PHASE.CHECKING_KEY || phase === PHASE.LOADING_VAULT || phase === PHASE.REQUESTING) && (
                        <motion.div key="loading" initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }}
                            className="bg-white/5 backdrop-blur-xl border border-white/10 rounded-3xl p-12 text-center">
                            <div className="relative mx-auto w-16 h-16 mb-6">
                                <div className="absolute inset-0 rounded-full border-2 border-violet-500/20" />
                                <div className="absolute inset-0 rounded-full border-t-2 border-violet-400 animate-spin" />
                            </div>
                            <p className="text-white/70 font-semibold">
                                {phase === PHASE.REQUESTING ? 'Submitting access request…' : 'Checking access status…'}
                            </p>
                        </motion.div>
                    )}

                    {/* ── Ready to Request ─────────────────────────────── */}
                    {phase === PHASE.READY_TO_REQUEST && (
                        <motion.div key="ready" initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }} exit={{ opacity: 0 }}
                            className="bg-white/5 backdrop-blur-xl border border-white/10 rounded-3xl p-10 text-center space-y-6">
                            <div className="w-16 h-16 bg-violet-500/10 rounded-full flex items-center justify-center mb-5 mx-auto border border-violet-400/20">
                                <Shield size={28} className="text-violet-400" />
                            </div>
                            <div>
                                <h2 className="text-xl font-bold text-white">Emergency Vault Access</h2>
                                <p className="text-white/50 text-sm mt-2">
                                    If the vault owner has been inactive for the required period, you can request access to their vault. They will have 24 hours to deny your request.
                                </p>
                            </div>
                            <div className="p-4 bg-blue-500/10 border border-blue-500/20 rounded-2xl text-left">
                                <p className="text-xs font-bold text-blue-300 mb-1.5">🔐 What happens next?</p>
                                <div className="text-[11px] text-blue-200/60 space-y-1">
                                    <p>1. We check if the owner has been inactive long enough.</p>
                                    <p>2. If yes, an access request is submitted.</p>
                                    <p>3. The owner gets 24 hours to deny. Otherwise, access is granted.</p>
                                </div>
                            </div>
                            <motion.button
                                id="emergency-request-access-btn"
                                whileTap={{ scale: 0.97 }}
                                onClick={handleRequestAccess}
                                className="w-full bg-gradient-to-r from-violet-600 to-indigo-600 text-white py-3.5 rounded-2xl font-bold shadow-lg shadow-violet-500/20 flex items-center justify-center gap-2 hover:opacity-90 transition-all"
                            >
                                <AlertTriangle size={16} /> Request Emergency Access
                            </motion.button>
                            <p className="text-white/30 text-xs">Contact ID: {contactId}</p>
                        </motion.div>
                    )}

                    {/* ── No Private Key ─────────────────────────────── */}
                    {phase === PHASE.NO_KEY && (
                        <motion.div key="nokey" initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }} exit={{ opacity: 0 }}
                            className="bg-white/5 backdrop-blur-xl border border-amber-500/20 rounded-3xl p-10 text-center">
                            <div className="w-16 h-16 bg-amber-500/10 rounded-full flex items-center justify-center mb-5 mx-auto">
                                <Key size={28} className="text-amber-400" />
                            </div>
                            <h2 className="text-xl font-bold text-white mb-2">Private Key Not Found</h2>
                            <p className="text-white/50 text-sm mb-6">
                                Your private key is not saved in this browser. Open the invite link on the original device, or import your key backup file.
                            </p>
                            <p className="text-white/30 text-xs">Contact ID: {contactId}</p>
                        </motion.div>
                    )}

                    {/* ── Waiting — Approval Window ──────────────────── */}
                    {phase === PHASE.WAITING && (
                        <motion.div key="waiting" initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }} exit={{ opacity: 0 }}
                            className="bg-white/5 backdrop-blur-xl border border-amber-500/20 rounded-3xl p-10 text-center space-y-5">
                            <div className="w-16 h-16 bg-amber-500/10 rounded-full flex items-center justify-center mx-auto border border-amber-400/20">
                                <Clock size={28} className="text-amber-400" />
                            </div>
                            <div>
                                <h2 className="text-xl font-bold text-white">Access Request Submitted</h2>
                                <p className="text-white/50 text-sm mt-2">
                                    The vault owner has been notified. They have 24 hours to deny. If no action is taken, access will be granted automatically.
                                </p>
                            </div>
                            {approvalDeadline && (
                                <div className="p-4 bg-amber-500/10 border border-amber-500/20 rounded-2xl">
                                    <p className="text-white/40 text-xs mb-1">Approval window closes in:</p>
                                    <Countdown deadline={approvalDeadline} />
                                </div>
                            )}
                            <button
                                id="emergency-check-status"
                                onClick={fetchVaultAccess}
                                className="flex items-center gap-2 mx-auto text-sm text-violet-400 hover:text-violet-300 transition-colors"
                            >
                                <RefreshCw size={13} /> Check Status
                            </button>
                        </motion.div>
                    )}

                    {/* ── Need Master Password ───────────────────────── */}
                    {phase === PHASE.NEED_MASTER && (
                        <motion.div key="master" initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }} exit={{ opacity: 0 }}
                            className="bg-white/5 backdrop-blur-xl border border-white/10 rounded-3xl p-8 space-y-5">
                            <div className="text-center">
                                <div className="w-14 h-14 bg-violet-500/20 rounded-2xl flex items-center justify-center mb-4 mx-auto border border-violet-400/20">
                                    <Lock size={24} className="text-violet-400" />
                                </div>
                                <h2 className="text-xl font-bold text-white">Access Granted!</h2>
                                <p className="text-white/50 text-sm mt-1">
                                    Enter <span className="font-bold text-white">{ownerName}'s</span> master password to decrypt their vault
                                </p>
                            </div>

                            {encMasterKeyBundle ? (
                                <div className="p-4 bg-green-500/10 border border-green-500/20 rounded-2xl">
                                    <div className="flex items-center gap-2 mb-1.5">
                                        <ShieldCheck size={14} className="text-green-400" />
                                        <p className="text-xs font-bold text-green-300">RSA Decryption Available</p>
                                    </div>
                                    <p className="text-[10px] text-green-200/50 leading-relaxed">
                                        We found your private key. If the owner has securely shared access, the vault will decrypt automatically. 
                                        If it doesn't, you can still enter the password manually below.
                                    </p>
                                </div>
                            ) : (
                                <div className="p-3 bg-blue-500/10 border border-blue-500/20 rounded-xl text-xs text-blue-200/70">
                                    <p className="font-bold text-blue-300 mb-0.5">🔐 Zero-Knowledge Preserved</p>
                                    Decryption happens only in your browser. We never see passwords.
                                </div>
                            )}
                            <div className="relative">
                                <input
                                    id="emergency-master-input"
                                    type={showMaster ? 'text' : 'password'}
                                    value={masterPassword}
                                    onChange={e => { setMasterPassword(e.target.value); setDecryptError(''); }}
                                    onKeyDown={e => e.key === 'Enter' && handleDecrypt()}
                                    placeholder="Owner's master password"
                                    className="w-full bg-white/10 border border-white/20 rounded-2xl px-5 py-3.5 text-white pr-12 focus:outline-none focus:border-violet-400/60 focus:ring-2 focus:ring-violet-500/20 transition-all"
                                />
                                <button onClick={() => setShowMaster(p => !p)}
                                    className="absolute right-4 top-1/2 -translate-y-1/2 text-white/40 hover:text-white/70 transition-colors">
                                    {showMaster ? <EyeOff size={16} /> : <Eye size={16} />}
                                </button>
                            </div>
                            {decryptError && <p className="text-red-400 text-xs font-semibold">{decryptError}</p>}
                            <motion.button whileTap={{ scale: 0.97 }} onClick={handleDecrypt}
                                disabled={!masterPassword}
                                className="w-full bg-gradient-to-r from-violet-600 to-indigo-600 text-white py-3.5 rounded-2xl font-bold flex items-center justify-center gap-2 shadow-lg shadow-violet-500/20 disabled:opacity-40 transition-all">
                                <Key size={16} /> Decrypt Vault
                            </motion.button>
                        </motion.div>
                    )}

                    {/* ── Vault Ready — Show Items ───────────────────── */}
                    {phase === PHASE.VAULT_READY && (
                        <motion.div key="vault" initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }} exit={{ opacity: 0 }}
                            className="space-y-4 pb-10">
                            <div className="flex items-center justify-between px-1 mb-2">
                                <div>
                                    <h2 className="text-lg font-bold text-white">{ownerName}'s Vault</h2>
                                    <p className="text-xs text-white/40">{decryptedItems.length} item{decryptedItems.length !== 1 ? 's' : ''} decrypted</p>
                                </div>
                                <div className="flex items-center gap-1.5 text-xs text-green-400 font-bold bg-green-500/10 border border-green-500/20 px-3 py-1.5 rounded-full">
                                    <CheckCircle2 size={11} /> Access Granted
                                </div>
                            </div>

                            {decryptedItems.map(item => (
                                <motion.div key={item.id} initial={{ opacity: 0, y: 5 }} animate={{ opacity: 1, y: 0 }}
                                    className="bg-white/5 backdrop-blur-xl border border-white/10 rounded-2xl p-5 space-y-3">
                                    <div className="flex items-center gap-3">
                                        <div className="w-9 h-9 rounded-xl bg-white/10 border border-white/10 flex items-center justify-center">
                                            <TypeIcon type={item.itemType} />
                                        </div>
                                        <div>
                                            <p className="font-bold text-white text-sm">{item.appName || 'Unknown'}</p>
                                            <p className="text-[10px] text-white/40 uppercase tracking-widest">{item.itemType || 'Login'}</p>
                                        </div>
                                    </div>
                                    <div className="space-y-2">
                                        {item.username && (
                                            <div className="flex items-center justify-between gap-2 p-2.5 bg-white/5 rounded-xl">
                                                <div>
                                                    <p className="text-[9px] text-white/30 uppercase tracking-widest">Username</p>
                                                    <p className="text-xs font-mono text-white/80">{item.username}</p>
                                                </div>
                                                <CopyBtn text={item.username} />
                                            </div>
                                        )}
                                        {item.password && (
                                            <div className="flex items-center justify-between gap-2 p-2.5 bg-white/5 rounded-xl">
                                                <div>
                                                    <p className="text-[9px] text-white/30 uppercase tracking-widest">Password</p>
                                                    <p className={`text-xs font-mono text-white/80 transition-all ${!showPasswords[item.id] ? 'blur-[4px]' : ''}`}>{item.password}</p>
                                                </div>
                                                <div className="flex gap-1">
                                                    <button onClick={() => setShowPasswords(p => ({ ...p, [item.id]: !p[item.id] }))}
                                                        className="p-1.5 rounded-lg bg-white/10 hover:bg-white/20 text-white/60 transition-all">
                                                        {showPasswords[item.id] ? <EyeOff size={12} /> : <Eye size={12} />}
                                                    </button>
                                                    <CopyBtn text={item.password} />
                                                </div>
                                            </div>
                                        )}
                                        {item.url && (
                                            <div className="flex items-center justify-between gap-2 p-2.5 bg-white/5 rounded-xl">
                                                <div>
                                                    <p className="text-[9px] text-white/30 uppercase tracking-widest">Website</p>
                                                    <p className="text-xs font-mono text-white/80">{item.url}</p>
                                                </div>
                                                <CopyBtn text={item.url} />
                                            </div>
                                        )}
                                        {item.note && (
                                            <div className="p-2.5 bg-white/5 rounded-xl">
                                                <p className="text-[9px] text-white/30 uppercase tracking-widest mb-1">Note</p>
                                                <p className="text-xs text-white/70 whitespace-pre-wrap">{item.note}</p>
                                            </div>
                                        )}
                                    </div>
                                </motion.div>
                            ))}
                        </motion.div>
                    )}

                    {/* ── Access Denied ──────────────────────────────── */}
                    {phase === PHASE.ACCESS_DENIED && (
                        <motion.div key="denied" initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }} exit={{ opacity: 0 }}
                            className="bg-white/5 backdrop-blur-xl border border-red-500/20 rounded-3xl p-10 text-center">
                            <div className="w-16 h-16 bg-red-500/10 rounded-full flex items-center justify-center mb-5 mx-auto">
                                <ShieldOff size={28} className="text-red-400" />
                            </div>
                            <h2 className="text-xl font-bold text-white mb-2">Access Denied</h2>
                            <p className="text-white/50 text-sm">The owner denied your access request. You may request again after the inactivity period.</p>
                        </motion.div>
                    )}

                    {/* ── Error ──────────────────────────────────────── */}
                    {phase === PHASE.ERROR && (
                        <motion.div key="error" initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }} exit={{ opacity: 0 }}
                            className="bg-white/5 backdrop-blur-xl border border-red-500/20 rounded-3xl p-10 text-center">
                            <ShieldOff size={32} className="text-red-400 mx-auto mb-4" />
                            <h2 className="text-xl font-bold text-white mb-2">Something Went Wrong</h2>
                            <p className="text-white/50 text-sm">{errorMsg}</p>
                        </motion.div>
                    )}

                </AnimatePresence>
            </div>
        </div>
    );
}

import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { motion, AnimatePresence } from 'framer-motion';
import { loginUser, registerUser, getHint, resetPassword as apiResetPassword, API_URL } from '../lib/api';
import { deriveKeys, generateRecoveryKey } from '../lib/crypto';
import useAuthStore from '../store/useAuthStore';
import useToastStore from '../store/useToastStore';
import {
    ShieldCheck, Mail, Lock, Eye, EyeOff, ArrowRight,
    UserPlus, LogIn, Loader2, Shield, User, Phone,
    KeyRound, AlertCircle, Copy, Check, ChevronLeft, Keyboard
} from 'lucide-react';
import clsx from 'clsx';
import VirtualKeyboard from '../components/VirtualKeyboard';
import { startAuthentication } from '@simplewebauthn/browser';

export default function Login() {
    const [isLogin, setIsLogin] = useState(true);
    const [email, setEmail] = useState('');
    const [loginPassword, setLoginPassword] = useState('');
    const [masterPassword, setMasterPassword] = useState('');
    const [name, setName] = useState('');
    const [phone, setPhone] = useState('');
    const [hint, setHint] = useState('');
    const [showLoginPassword, setShowLoginPassword] = useState(false);
    const [showMasterPassword, setShowMasterPassword] = useState(false);
    const [showKeyboard, setShowKeyboard] = useState(false);
    const [error, setError] = useState('');
    const [loading, setLoading] = useState(false);

    // Recovery System states
    const [recoveryKey, setRecoveryKey] = useState('');
    const [showRecoveryModal, setShowRecoveryModal] = useState(false);
    const [forgotMode, setForgotMode] = useState(null); // 'email', 'hint', 'reset'
    const [resetEmail, setResetEmail] = useState('');
    const [foundHint, setFoundHint] = useState('');
    const [userRecoveryKey, setUserRecoveryKey] = useState('');
    const [newPassword, setNewPassword] = useState('');
    const [confirmPassword, setConfirmPassword] = useState('');
    const [copied, setCopied] = useState(false);

    const navigate = useNavigate();
    const { setUser, setMasterKey } = useAuthStore();
    const { addToast } = useToastStore();

    const handleAuth = async (e) => {
        e.preventDefault();
        setLoading(true);
        setError('');

        try {
            if (!email.includes('@')) throw new Error("Please enter a valid email");
            if (loginPassword.length < 8) throw new Error("Login password must be at least 8 chars");
            if (!isLogin && masterPassword.length < 8) throw new Error("Master password must be at least 8 chars");

            let data;
            if (isLogin) {
                const { authKey } = deriveKeys(loginPassword, email); // V1 fallback hash derivation
                data = await loginUser(email, loginPassword, authKey);
                addToast(`Welcome back, ${data.name || email.split('@')[0]}`, 'success');
                // No setMasterKey here, User is prompted upon entering the app
                setUser({
                    uid: data.uid,
                    email: data.email,
                    name: data.name,
                    phoneNumber: data.phoneNumber,
                    role: data.role
                });
                navigate('/');
            } else {
                const { authKey, encKey } = deriveKeys(masterPassword, email);
                const masterAuthHash = authKey; // We use authKey to communicate with server

                const newRecoveryKey = generateRecoveryKey();
                // To keep ZK, we must hash the recovery key on server, but we show it to user once.
                data = await registerUser(name, email, phone, loginPassword, masterAuthHash, hint, newRecoveryKey);

                setMasterKey(encKey); // Save EncKey for the session since we have the master password
                setRecoveryKey(newRecoveryKey);
                setShowRecoveryModal(true); // Modal will navigate to home when closed

                // We don't navigate yet, user must see recovery key
                setUser({
                    uid: data.uid,
                    email: data.email,
                    name: data.name,
                    phoneNumber: data.phoneNumber,
                    role: data.role
                });
            }
        } catch (err) {
            setError(err.message);
            addToast(err.message, 'error');
        } finally {
            setLoading(false);
        }
    };

    const handleGetHint = async (e) => {
        e.preventDefault();
        setLoading(true);
        try {
            const data = await getHint(resetEmail);
            setFoundHint(data.hint);
            setForgotMode('hint');
        } catch (err) {
            addToast(err.message, 'error');
        } finally {
            setLoading(false);
        }
    };

    const handleResetPassword = async (e) => {
        e.preventDefault();
        if (newPassword !== confirmPassword) return addToast("Passwords do not match", "error");
        if (newPassword.length < 8) return addToast("Min 8 characters", "error");

        setLoading(true);
        try {
            const { authKey, encKey } = deriveKeys(newPassword, resetEmail);
            await apiResetPassword(resetEmail, userRecoveryKey, authKey);
            setMasterKey(encKey);
            addToast("Password reset successful! Please login.", "success");
            setForgotMode(null);
            setEmail(resetEmail);
            setIsLogin(true);
        } catch (err) {
            addToast(err.message, 'error');
        } finally {
            setLoading(false);
        }
    };

    const handlePasskeyLogin = async () => {
        if (!email) return addToast("Please enter your email first", "warning");
        setLoading(true);
        try {
            const resp = await fetch(`${API_URL}/passkeys/generate-auth-options`, {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ email })
            });

            if (!resp.ok) {
                const data = await resp.json();
                throw new Error(data.message || 'Passkey login failed');
            }

            const options = await resp.json();
            const asseResp = await startAuthentication({ optionsJSON: options });

            const verifyResp = await fetch(`${API_URL}/passkeys/verify-auth`, {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ email, response: asseResp }),
                credentials: 'include'
            });

            if (verifyResp.ok) {
                const data = await verifyResp.json();
                if (data.verified) {
                    addToast(`Welcome back! Passkey authenticated.`, 'success');

                    // NOTE: Passkeys bypass the Master Password, which means we CANNOT derive the vault decryption key (encKey).
                    // In a true Zero-Knowledge system, passkeys should decrypt a securely stored wrapped master key, or they can only be used for 2FA.
                    // For this simplified demo/phase, we'll log the user in, but they will need to type their master password once to decrypt the vault.
                    setUser({
                        uid: data.uid,
                        email: data.email,
                        name: data.name,
                        phoneNumber: data.phoneNumber,
                        role: data.role
                    });
                    navigate('/'); // Go to dashboard, but prompt for Master Key there if missing
                }
            } else {
                throw new Error('Passkey verification failed');
            }
        } catch (error) {
            console.error(error);
            if (error.name === 'NotAllowedError') {
                addToast('Passkey login cancelled', 'info');
            } else {
                addToast(error.message || 'Passkey authentication failed', 'error');
            }
        } finally {
            setLoading(false);
        }
    };

    const copyRecoveryKey = () => {
        navigator.clipboard.writeText(recoveryKey);
        setCopied(true);
        addToast("Recovery Key copied to clipboard!", "success");
        setTimeout(() => setCopied(false), 2000);
    };

    return (
        <div className="min-h-screen w-full flex items-center justify-center bg-[#020617] relative p-4 overflow-hidden selection:bg-primary/30">

            {/* Dynamic Background Mesh */}
            <div className="absolute inset-0 z-0">
                <motion.div
                    animate={{
                        x: [0, 40, 0],
                        y: [0, -40, 0],
                        scale: [1, 1.1, 1]
                    }}
                    transition={{ duration: 15, repeat: Infinity, ease: "easeInOut" }}
                    className="absolute top-[-10%] left-[-10%] w-[50%] h-[50%] bg-primary/20 rounded-full blur-[120px]"
                />
                <motion.div
                    animate={{
                        x: [0, -30, 0],
                        y: [0, 50, 0],
                        scale: [1, 1.2, 1]
                    }}
                    transition={{ duration: 18, repeat: Infinity, ease: "easeInOut" }}
                    className="absolute bottom-[-10%] right-[-10%] w-[60%] h-[60%] bg-blue-500/10 rounded-full blur-[140px]"
                />
                <div className="absolute inset-0 bg-black/20 opacity-[0.03] pointer-events-none mix-blend-overlay"></div>
            </div>

            <motion.div
                initial={{ opacity: 0, y: 30 }}
                animate={{ opacity: 1, y: 0 }}
                transition={{ duration: 0.8, ease: "easeOut" }}
                className="w-full max-w-[440px] z-10"
            >
                {/* Logo Section */}
                <div className="flex flex-col items-center mb-8">
                    <motion.div
                        initial={{ scale: 0, rotate: -20 }}
                        animate={{ scale: 1, rotate: 0 }}
                        transition={{ type: "spring", stiffness: 260, damping: 20, delay: 0.2 }}
                        className="w-16 h-16 bg-primary/20 backdrop-blur-xl border border-primary/30 rounded-2xl flex items-center justify-center shadow-2xl shadow-primary/20 mb-4"
                    >
                        <ShieldCheck size={36} className="text-primary" />
                    </motion.div>
                    <h1 className="text-3xl font-extrabold tracking-tight text-white mb-1">
                        Password <span className="text-primary">Keeper X</span>
                    </h1>
                    <p className="text-slate-400 text-sm font-medium tracking-wide border-b border-primary/20 pb-1">Zero-Knowledge Vault</p>
                </div>

                {/* Main Auth Card */}
                <div className="bg-slate-900/40 backdrop-blur-2xl border border-white/10 rounded-[2.5rem] p-6 sm:p-8 md:p-10 shadow-2xl relative overflow-hidden group">
                    <div className="absolute top-0 left-0 w-full h-[2px] bg-gradient-to-r from-transparent via-primary/50 to-transparent"></div>

                    <AnimatePresence mode="wait">
                        {forgotMode ? (
                            <motion.div
                                key="forgot"
                                initial={{ opacity: 0, x: 20 }}
                                animate={{ opacity: 1, x: 0 }}
                                exit={{ opacity: 0, x: -20 }}
                                className="space-y-6"
                            >
                                <button 
                                    onClick={() => setForgotMode(null)}
                                    className="flex items-center gap-2 text-slate-500 hover:text-primary transition-colors text-xs font-bold uppercase tracking-widest mb-4"
                                >
                                    <ChevronLeft size={16} /> Back to Login
                                </button>

                                <div className="mb-6">
                                    <h2 className="text-2xl font-bold text-white mb-2">Account Recovery</h2>
                                    <p className="text-slate-400 text-sm">
                                        {forgotMode === 'email' ? "Enter your email to find your hint." : 
                                         forgotMode === 'hint' ? "Review your hint. If you still can't remember, use your Recovery Key." :
                                         "Reset your master password using your Recovery Key."}
                                    </p>
                                </div>

                                {forgotMode === 'email' && (
                                    <form onSubmit={handleGetHint} className="space-y-4">
                                        <div className="space-y-1">
                                            <div className="relative group/input">
                                                <div className="absolute inset-y-0 left-3 flex items-center text-slate-500">
                                                    <Mail size={18} />
                                                </div>
                                                <input
                                                    type="email"
                                                    value={resetEmail}
                                                    onChange={(e) => setResetEmail(e.target.value)}
                                                    placeholder="Enter your email"
                                                    className="w-full bg-slate-950/50 border border-slate-800 rounded-2xl py-3.5 pl-10 pr-4 text-white placeholder:text-slate-600 focus:outline-none focus:ring-2 focus:ring-primary/20 transition-all font-medium text-sm"
                                                    required
                                                />
                                            </div>
                                        </div>
                                        <button 
                                            type="submit" disabled={loading}
                                            className="w-full py-4 bg-primary text-primary-foreground rounded-2xl font-bold flex items-center justify-center gap-2"
                                        >
                                            {loading ? <Loader2 className="animate-spin" size={20} /> : "Find My Hint"}
                                        </button>
                                    </form>
                                )}

                                {forgotMode === 'hint' && (
                                    <div className="space-y-6">
                                        <div className="p-5 rounded-2xl bg-primary/5 border border-primary/10">
                                            <p className="text-xs font-bold text-primary uppercase tracking-widest mb-2">Your Password Hint</p>
                                            <p className="text-lg text-white font-medium italic">"{foundHint}"</p>
                                        </div>
                                        <div className="flex flex-col gap-3">
                                            <button 
                                                onClick={() => setForgotMode(null)}
                                                className="w-full py-3 bg-white/10 hover:bg-white/20 text-white rounded-xl font-bold transition-all text-sm"
                                            >
                                                I Remember Now
                                            </button>
                                            <button 
                                                onClick={() => setForgotMode('reset')}
                                                className="w-full py-3 bg-primary/20 hover:bg-primary/30 text-primary rounded-xl font-bold transition-all text-sm"
                                            >
                                                Still Locked? Use Recovery Key
                                            </button>
                                        </div>
                                    </div>
                                )}

                                {forgotMode === 'reset' && (
                                    <form onSubmit={handleResetPassword} className="space-y-4">
                                        <div className="space-y-3">
                                            <input
                                                type="text"
                                                value={userRecoveryKey}
                                                onChange={(e) => setUserRecoveryKey(e.target.value.toUpperCase())}
                                                placeholder="XXXX-XXXX-XXXX"
                                                className="w-full bg-slate-950/50 border border-slate-800 rounded-2xl py-3.5 px-4 text-white placeholder:text-slate-600 focus:outline-none focus:ring-2 focus:ring-primary/20 transition-all font-bold tracking-widest text-center"
                                                required
                                            />
                                            <div className="relative group/input">
                                                <div className="absolute inset-y-0 left-3 flex items-center text-slate-500">
                                                    <Lock size={18} />
                                                </div>
                                                <input
                                                    type="password"
                                                    value={newPassword}
                                                    onChange={(e) => setNewPassword(e.target.value)}
                                                    placeholder="New Master Password"
                                                    className="w-full bg-slate-950/50 border border-slate-800 rounded-2xl py-3.5 pl-10 pr-4 text-white placeholder:text-slate-600 focus:outline-none focus:ring-2 focus:ring-primary/20 transition-all font-medium text-sm tracking-widest"
                                                    required
                                                />
                                            </div>
                                            <input
                                                type="password"
                                                value={confirmPassword}
                                                onChange={(e) => setConfirmPassword(e.target.value)}
                                                placeholder="Confirm New Password"
                                                className="w-full bg-slate-950/50 border border-slate-800 rounded-2xl py-3.5 px-4 text-white placeholder:text-slate-600 focus:outline-none focus:ring-2 focus:ring-primary/20 transition-all font-medium text-sm tracking-widest"
                                                required
                                            />
                                        </div>
                                        <button 
                                            type="submit" disabled={loading}
                                            className="w-full py-4 bg-primary text-primary-foreground rounded-2xl font-bold flex items-center justify-center gap-2"
                                        >
                                            {loading ? <Loader2 className="animate-spin" size={20} /> : "Reset Vault Password"}
                                        </button>
                                        <p className="text-[10px] text-center text-red-400 font-bold uppercase px-4 leading-relaxed">
                                            Warning: This key is your only way back. If lost, your data is gone forever.
                                        </p>
                                    </form>
                                )}
                            </motion.div>
                        ) : (
                            <motion.div
                                key={isLogin ? 'login' : 'signup'}
                                initial={{ opacity: 0, x: 20 }}
                                animate={{ opacity: 1, x: 0 }}
                                exit={{ opacity: 0, x: -20 }}
                                transition={{ duration: 0.4, ease: "circOut" }}
                            >
                            <div className="mb-8">
                                <h2 className="text-2xl font-bold text-white mb-2">
                                    {isLogin ? 'Welcome back' : 'Get started'}
                                </h2>
                                <p className="text-slate-400 text-sm">
                                    {isLogin
                                        ? 'Unlock your credentials with your master identity.'
                                        : 'Create your private vault today. It takes less than a minute.'}
                                </p>
                            </div>

                            <form onSubmit={handleAuth} className="space-y-5">
                                {!isLogin && (
                                    <motion.div
                                        initial={{ opacity: 0, height: 0 }}
                                        animate={{ opacity: 1, height: 'auto' }}
                                        className="space-y-4"
                                    >
                                        <div className="space-y-1">
                                            <label className="text-xs font-bold text-slate-500 uppercase tracking-widest ml-1">Full Name</label>
                                            <div className="relative group/input">
                                                <div className="absolute inset-y-0 left-3 flex items-center text-slate-500 group-focus-within/input:text-primary transition-colors">
                                                    <User size={18} />
                                                </div>
                                                <input
                                                    type="text"
                                                    value={name}
                                                    onChange={(e) => setName(e.target.value)}
                                                    placeholder="Ritu Raj"
                                                    className="w-full bg-slate-950/50 border border-slate-800 rounded-2xl py-3.5 pl-10 pr-4 text-white placeholder:text-slate-600 focus:outline-none focus:ring-2 focus:ring-primary/20 focus:border-primary/50 transition-all font-medium text-sm"
                                                    required={!isLogin}
                                                />
                                            </div>
                                        </div>
                                        <div className="space-y-1">
                                            <label className="text-xs font-bold text-slate-500 uppercase tracking-widest ml-1">Phone Number</label>
                                            <div className="relative group/input">
                                                <div className="absolute inset-y-0 left-3 flex items-center text-slate-500 group-focus-within/input:text-primary transition-colors">
                                                    <Phone size={18} />
                                                </div>
                                                <input
                                                    type="tel"
                                                    value={phone}
                                                    onChange={(e) => setPhone(e.target.value)}
                                                    placeholder="+91 99999-00000"
                                                    className="w-full bg-slate-950/50 border border-slate-800 rounded-2xl py-3.5 pl-10 pr-4 text-white placeholder:text-slate-600 focus:outline-none focus:ring-2 focus:ring-primary/20 focus:border-primary/50 transition-all font-medium text-sm"
                                                />
                                            </div>
                                        </div>
                                        <div className="space-y-1">
                                            <label className="text-xs font-bold text-slate-500 uppercase tracking-widest ml-1">Password Hint</label>
                                            <div className="relative group/input">
                                                <div className="absolute inset-y-0 left-3 flex items-center text-slate-500 group-focus-within/input:text-primary transition-colors">
                                                    <AlertCircle size={18} />
                                                </div>
                                                <input
                                                    type="text"
                                                    value={hint}
                                                    onChange={(e) => setHint(e.target.value)}
                                                    placeholder="Something to help you remember"
                                                    className="w-full bg-slate-950/50 border border-slate-800 rounded-2xl py-3.5 pl-10 pr-4 text-white placeholder:text-slate-600 focus:outline-none focus:ring-2 focus:ring-primary/20 focus:border-primary/50 transition-all font-medium text-sm"
                                                    required={!isLogin}
                                                />
                                            </div>
                                        </div>
                                    </motion.div>
                                )}

                                <div className="space-y-1">
                                    <label className="text-xs font-bold text-slate-500 uppercase tracking-widest ml-1">Email Address</label>
                                    <div className="relative group/input">
                                        <div className="absolute inset-y-0 left-3 flex items-center text-slate-500 group-focus-within/input:text-primary transition-colors">
                                            <Mail size={18} />
                                        </div>
                                        <input
                                            type="email"
                                            value={email}
                                            onChange={(e) => setEmail(e.target.value)}
                                            placeholder="name@example.com"
                                            className="w-full bg-slate-950/50 border border-slate-800 rounded-2xl py-3.5 pl-10 pr-4 text-white placeholder:text-slate-600 focus:outline-none focus:ring-2 focus:ring-primary/20 focus:border-primary/50 transition-all font-medium text-sm"
                                            required
                                            autoComplete="email"
                                        />
                                    </div>
                                </div>

                                <div className="space-y-1">
                                    <div className="flex justify-between items-center ml-1">
                                        <label className="text-xs font-bold text-slate-500 uppercase tracking-widest">
                                            {isLogin ? 'Login Password' : 'Account Login Password'}
                                        </label>
                                        {isLogin && (
                                            <button 
                                                type="button" 
                                                onClick={() => { setForgotMode('email'); setResetEmail(email); }}
                                                className="text-[10px] font-bold text-primary hover:underline uppercase tracking-tighter opacity-70"
                                            >
                                                Forgot Password?
                                            </button>
                                        )}
                                    </div>
                                    <div className="relative group/input">
                                        <div className="absolute inset-y-0 left-3 flex items-center text-slate-500 group-focus-within/input:text-primary transition-colors">
                                            <Lock size={18} />
                                        </div>
                                        <input
                                            type={showLoginPassword ? "text" : "password"}
                                            value={loginPassword}
                                            onChange={(e) => setLoginPassword(e.target.value)}
                                            placeholder="••••••••••••"
                                            className="w-full bg-slate-950/50 border border-slate-800 rounded-2xl py-3.5 pl-10 pr-12 text-white placeholder:text-slate-600 focus:outline-none focus:ring-2 focus:ring-primary/20 focus:border-primary/50 transition-all font-medium text-sm tracking-widest"
                                            required
                                            autoComplete={isLogin ? "current-password" : "new-password"}
                                        />
                                        <button
                                            type="button"
                                            onClick={() => setShowLoginPassword(!showLoginPassword)}
                                            className="absolute inset-y-0 right-3 flex items-center text-slate-500 hover:text-white transition-colors"
                                        >
                                            {showLoginPassword ? <EyeOff size={18} /> : <Eye size={18} />}
                                        </button>
                                    </div>
                                    {isLogin && (
                                    <div className="flex justify-end pt-1">
                                        <button 
                                            type="button" 
                                            onClick={() => setShowKeyboard(!showKeyboard)}
                                            className="text-[10px] font-bold uppercase tracking-widest text-slate-500 flex items-center gap-1 hover:text-primary transition-colors"
                                        >
                                            <Keyboard size={12} /> {showKeyboard ? 'Hide Pad' : 'Use Secure Pad'}
                                        </button>
                                    </div>
                                    )}
                                </div>

                                {showKeyboard && isLogin && (
                                    <VirtualKeyboard 
                                       onKeyPress={(char) => setLoginPassword(prev => prev + char)} 
                                       onBackspace={() => setLoginPassword(prev => prev.slice(0, -1))}
                                       onClose={() => setShowKeyboard(false)}
                                    />
                                )}

                                {!isLogin && (
                                <div className="space-y-1 mt-4">
                                    <label className="text-xs font-bold text-primary uppercase tracking-widest ml-1">Vault Master Password</label>
                                    <div className="relative group/input">
                                        <div className="absolute inset-y-0 left-3 flex items-center text-slate-500 group-focus-within/input:text-primary transition-colors">
                                            <Shield size={18} />
                                        </div>
                                        <input
                                            type={showMasterPassword ? "text" : "password"}
                                            value={masterPassword}
                                            onChange={(e) => setMasterPassword(e.target.value)}
                                            placeholder="••••••••••••"
                                            className="w-full bg-slate-950/50 border border-slate-800 rounded-2xl py-3.5 pl-10 pr-12 text-white placeholder:text-slate-600 focus:outline-none focus:ring-2 focus:ring-primary/20 focus:border-primary/50 transition-all font-medium text-sm tracking-widest border-primary/30"
                                            required
                                            autoComplete="new-password"
                                        />
                                        <button
                                            type="button"
                                            onClick={() => setShowMasterPassword(!showMasterPassword)}
                                            className="absolute inset-y-0 right-3 flex items-center text-slate-500 hover:text-white transition-colors"
                                        >
                                            {showMasterPassword ? <EyeOff size={18} /> : <Eye size={18} />}
                                        </button>
                                    </div>
                                    <div className="flex justify-end pt-1">
                                        <button 
                                            type="button" 
                                            onClick={() => setShowKeyboard(!showKeyboard)}
                                            className="text-[10px] font-bold uppercase tracking-widest text-slate-500 flex items-center gap-1 hover:text-primary transition-colors"
                                        >
                                            <Keyboard size={12} /> {showKeyboard ? 'Hide Pad' : 'Use Secure Pad'}
                                        </button>
                                    </div>
                                </div>
                                )}

                                {showKeyboard && !isLogin && (
                                    <VirtualKeyboard 
                                       onKeyPress={(char) => setMasterPassword(prev => prev + char)} 
                                       onBackspace={() => setMasterPassword(prev => prev.slice(0, -1))}
                                       onClose={() => setShowKeyboard(false)}
                                    />
                                )}

                                <motion.button
                                    whileHover={{ scale: 1.01 }}
                                    whileTap={{ scale: 0.99 }}
                                    type="submit"
                                    disabled={loading}
                                    className={clsx(
                                        "w-full py-4 rounded-2xl font-bold text-sm tracking-wide shadow-xl transition-all flex items-center justify-center gap-2",
                                        isLogin
                                            ? "bg-primary text-primary-foreground shadow-primary/20 hover:shadow-primary/40"
                                            : "bg-white text-black hover:bg-slate-100 shadow-white/10"
                                    )}
                                >
                                    {loading ? <Loader2 className="animate-spin" size={20} /> : (isLogin ? <LogIn size={20} /> : <UserPlus size={20} />)}
                                    {loading ? 'Authenticating...' : (isLogin ? 'Sign In to Vault' : 'Create My Vault')}
                                </motion.button>

                                {isLogin && (
                                    <div className="pt-2">
                                        <div className="relative flex py-2 items-center">
                                            <div className="flex-grow border-t border-slate-800"></div>
                                            <span className="flex-shrink-0 mx-4 text-slate-500 text-xs font-bold uppercase tracking-widest">Or access with</span>
                                            <div className="flex-grow border-t border-slate-800"></div>
                                        </div>
                                        <button
                                            type="button"
                                            onClick={handlePasskeyLogin}
                                            disabled={loading}
                                            className="w-full mt-2 py-3.5 rounded-2xl font-bold text-sm tracking-wide bg-primary/10 text-primary hover:bg-primary/20 transition-all flex items-center justify-center gap-2 border border-primary/20"
                                        >
                                            <KeyRound size={20} /> Sign in with Passkey / Biometrics
                                        </button>
                                    </div>
                                )}
                            </form>

