            <p className="font-bold mb-0.5">{label}</p>
            <p className="text-primary font-black">{payload[0].value} item{payload[0].value !== 1 ? 's' : ''}</p>
        </div>
    );
};

const CustomPieTooltip = ({ active, payload }) => {
